-- Discover pilot import: age bands 1–3 months, 13–15 months, 16–18 months, 4–6 months, 9–12 months
-- Source: discover_projection tab from Ember ABI workbooks (1-3m + 13-15m + 16-18m + 4-6m + 9-12m)
-- Stage 3 intentionally empty. Idempotent: safe to re-run.

BEGIN;

CREATE TEMP TABLE tmp_discover_projection_stage (
  age_band_id TEXT NOT NULL,
  age_band_label TEXT NOT NULL,
  min_months INTEGER NOT NULL,
  max_months INTEGER NOT NULL,
  age_band_is_active BOOLEAN NOT NULL,
  stage1_wrapper_ux_slug TEXT NOT NULL,
  stage1_wrapper_ux_label TEXT NOT NULL,
  stage1_wrapper_rank_in_band INTEGER NOT NULL,
  stage1_mapping_is_active BOOLEAN NOT NULL,
  development_need_slug TEXT NOT NULL,
  development_need_canonical_name TEXT NOT NULL,
  stage1_why_it_matters_ux_description TEXT,
  audience_lens TEXT,
  stage2_category_type_slug TEXT NOT NULL,
  stage2_category_type_label TEXT NOT NULL,
  stage2_category_type_name TEXT NOT NULL,
  stage2_play_ideas_rank INTEGER NOT NULL,
  stage2_play_idea_mapping_rationale TEXT,
  category_audience_lens TEXT
) ON COMMIT DROP;

INSERT INTO tmp_discover_projection_stage (
  age_band_id,
  age_band_label,
  min_months,
  max_months,
  age_band_is_active,
  stage1_wrapper_ux_slug,
  stage1_wrapper_ux_label,
  stage1_wrapper_rank_in_band,
  stage1_mapping_is_active,
  development_need_slug,
  development_need_canonical_name,
  stage1_why_it_matters_ux_description,
  audience_lens,
  stage2_category_type_slug,
  stage2_category_type_label,
  stage2_category_type_name,
  stage2_play_ideas_rank,
  stage2_play_idea_mapping_rationale,
  category_audience_lens
)
VALUES
  ('1-3m','1–3 months',1,3,true,'ent_cluster_faces_smiles_chats','I’m finding your face',1,true,'ent_need_face_smile_chat','Finding your face','Your baby may be watching your face, softening when you speak and trying tiny coos or smiles. These little back-and-forth moments make everyday cuddles, changes and floor play feel shared, while supporting connection, attention and early communication. Your voice, face and pauses are enough.','for_your_child','cat_face_to_face_play','Face-to-face talking and smiling','Face To Face Play',1,'Your baby may be watching your face closely and beginning to answer with little sounds or smiles. Talking, smiling, pausing and copying expressions gives them a simple back-and-forth moment that supports bonding and early communication. Keep it short, gentle and led by what your baby seems ready for.','for_your_child'),
  ('1-3m','1–3 months',1,3,true,'ent_cluster_faces_smiles_chats','I’m finding your face',1,true,'ent_need_face_smile_chat','Finding your face','Your baby may be watching your face, softening when you speak and trying tiny coos or smiles. These little back-and-forth moments make everyday cuddles, changes and floor play feel shared, while supporting connection, attention and early communication. Your voice, face and pauses are enough.','for_your_child','cat_copying_faces_expressions','Copying faces and little expressions','Copying Faces Expressions',2,'Your baby may begin copying tiny facial expressions, such as a tongue out or a wide-eyed look. Turning those moments into a gentle game helps them practise watching, waiting and responding, while keeping connection at the centre. Keep it short, gentle and led by what your baby seems ready for.','for_your_child'),
  ('1-3m','1–3 months',1,3,true,'ent_cluster_faces_smiles_chats','I’m finding your face',1,true,'ent_need_face_smile_chat','Finding your face','Your baby may be watching your face, softening when you speak and trying tiny coos or smiles. These little back-and-forth moments make everyday cuddles, changes and floor play feel shared, while supporting connection, attention and early communication. Your voice, face and pauses are enough.','for_your_child','cat_baby_safe_mirror','A baby-safe mirror for faces','Baby Safe Mirror',3,'A baby-safe mirror can make a few minutes of awake play feel more interesting. Your baby will not understand the reflection yet, but faces, movement and your voice nearby can help hold their attention during floor or tummy-time moments. Keep it short, gentle and led by what your baby seems ready for.','for_your_child'),
  ('1-3m','1–3 months',1,3,true,'ent_cluster_listen_and_coo','I’m listening to your voice',2,true,'ent_need_face_smile_chat','Listening to familiar voices','Your baby may pause when they hear you, turn towards a sound, or answer with a tiny coo. Gentle songs, familiar voices and simple rhythm help them connect listening with comfort, attention and early conversation. Short, repeated moments are enough at this stage.','for_your_child','cat_familiar_voice_pauses','Familiar voices and little pauses','Familiar Voice Pauses',1,'Your baby may quieten, look or coo when they hear a familiar voice. A simple pattern of talk, pause, wait and answer gives them time to process sound and try their own tiny response, without needing a toy at all.','for_your_child'),
  ('1-3m','1–3 months',1,3,true,'ent_cluster_listen_and_coo','I’m listening to your voice',2,true,'ent_need_face_smile_chat','Listening to familiar voices','Your baby may pause when they hear you, turn towards a sound, or answer with a tiny coo. Gentle songs, familiar voices and simple rhythm help them connect listening with comfort, attention and early conversation. Short, repeated moments are enough at this stage.','for_your_child','cat_songs_action_games','Songs, rhymes and tiny games','Songs Action Games',2,'A short song, silly face or gentle peekaboo gives your baby sound, rhythm and expression to tune into. The pauses matter too, because they invite your baby to look, wriggle, coo or smile back in their own tiny way. Keep it short, gentle and led by what your baby seems ready for.','for_your_child'),
  ('1-3m','1–3 months',1,3,true,'ent_cluster_listen_and_coo','I’m listening to your voice',2,true,'ent_need_face_smile_chat','Listening to familiar voices','Your baby may pause when they hear you, turn towards a sound, or answer with a tiny coo. Gentle songs, familiar voices and simple rhythm help them connect listening with comfort, attention and early conversation. Short, repeated moments are enough at this stage.','for_your_child','cat_board_books','Board books and face books','Board Books',3,'Reading at this stage is less about the story and more about your voice, rhythm and closeness. A chunky board book, wooden book or face book gives your baby something to look at while you name, pause and repeat. Keep it short, gentle and led by what your baby seems ready for.','for_your_child'),
  ('1-3m','1–3 months',1,3,true,'ent_cluster_listen_and_coo','I’m listening to your voice',2,true,'ent_need_visual_tracking','Listening to familiar voices','Your baby may pause when they hear you, turn towards a sound, or answer with a tiny coo. Gentle songs, familiar voices and simple rhythm help them connect listening with comfort, attention and early conversation. Short, repeated moments are enough at this stage.','for_your_child','cat_sound_cylinders_shakers','Gentle shakers and sound toys','Sound Cylinders Shakers',4,'A soft shaker or gentle sound toy can help your baby notice where sound comes from. Keep it calm and close, because the value is not noise, it is the little turn, pause or widening eyes that shows they are tuning in.','for_your_child'),
  ('1-3m','1–3 months',1,3,true,'ent_cluster_watching_tracking','I’m watching the world',3,true,'ent_need_visual_tracking','Watching the world','Your baby may fix on a face, bold pattern or slow-moving object for a few seconds. Simple things to watch can help them practise focus, tracking and turning their head, without overstimulation. Keep it slow, close and easy to follow.','for_your_child','cat_high_contrast_cards','High-contrast cards and simple patterns','High Contrast Cards',1,'At this age, a simple pattern, face or bold shape can be enough. High-contrast cards or pages give your baby something easy to look at during short awake windows, while you slowly move, pause and talk alongside them. Keep it short, gentle and led by what your baby seems ready for.','for_your_child'),
  ('1-3m','1–3 months',1,3,true,'ent_cluster_watching_tracking','I’m watching the world',3,true,'ent_need_visual_tracking','Watching the world','Your baby may fix on a face, bold pattern or slow-moving object for a few seconds. Simple things to watch can help them practise focus, tracking and turning their head, without overstimulation. Keep it slow, close and easy to follow.','for_your_child','cat_tracking_rattle','A slow-moving rattle to track','Tracking Rattle',2,'A gentle rattle gives your baby one sound and movement to follow. Move it slowly, pause often and watch whether they turn, look or settle on it for a few seconds. That tiny focus is the point. Keep it short, gentle and led by what your baby seems ready for.','for_your_child'),
  ('1-3m','1–3 months',1,3,true,'ent_cluster_watching_tracking','I’m watching the world',3,true,'ent_need_visual_tracking','Watching the world','Your baby may fix on a face, bold pattern or slow-moving object for a few seconds. Simple things to watch can help them practise focus, tracking and turning their head, without overstimulation. Keep it slow, close and easy to follow.','for_your_child','cat_contrast_mobile_supervised','A supervised mobile or moving object','Contrast Mobile Supervised',3,'A slow moving object can give your baby a calm looking game. The key is supervision and simplicity: move slowly, pause, and keep anything loose or dangling away from the cot once your baby is sleeping. Keep it short, gentle and led by what your baby seems ready for.','for_your_child'),
  ('1-3m','1–3 months',1,3,true,'ent_cluster_tummy_head_control','I’m getting stronger on my tummy',4,true,'ent_need_tummy_head_control','Getting stronger on my tummy','Your baby may only manage a minute or two on their tummy at first. That is still useful. Short, supervised floor moments help them practise lifting, turning and settling into their body, while building the neck, shoulder and back strength that later supports rolling and reaching.','for_your_child','cat_tummy_time_mat','A simple tummy-time mat','Tummy Time Mat',1,'Tummy time can be tiny at first. A clean, firm floor mat gives your baby a safe awake place to practise lifting, turning and resting, while giving you one clear spot to return to without overcomplicating it. Keep it short, gentle and led by what your baby seems ready for.','for_your_child'),
  ('1-3m','1–3 months',1,3,true,'ent_cluster_tummy_head_control','I’m getting stronger on my tummy',4,true,'ent_need_tummy_head_control','Getting stronger on my tummy','Your baby may only manage a minute or two on their tummy at first. That is still useful. Short, supervised floor moments help them practise lifting, turning and settling into their body, while building the neck, shoulder and back strength that later supports rolling and reaching.','for_your_child','cat_tummy_time_wobbler','Tummy-time mirror or wobbler','Tummy Time Wobbler',2,'Some babies protest tummy time quickly. A small mirror, wobbly toy or crinkle object placed nearby can give them a reason to lift, look or turn for a moment, while you keep the session short and close. Keep it short, gentle and led by what your baby seems ready for.','for_your_child'),
  ('1-3m','1–3 months',1,3,true,'ent_cluster_tummy_head_control','I’m getting stronger on my tummy',4,true,'ent_need_tummy_head_control','Getting stronger on my tummy','Your baby may only manage a minute or two on their tummy at first. That is still useful. Short, supervised floor moments help them practise lifting, turning and settling into their body, while building the neck, shoulder and back strength that later supports rolling and reaching.','for_your_child','cat_rolled_towel_tummy_support','Rolled-towel tummy support','Rolled Towel Tummy Support',3,'A small rolled towel under your baby’s arms can sometimes make tummy time feel more manageable. It is not a must-have product, just a supervised setup trick for moments when your baby needs a little support to lift and look.','for_your_child'),
  ('1-3m','1–3 months',1,3,true,'ent_cluster_tummy_head_control','I’m getting stronger on my tummy',4,true,'ent_need_tummy_head_control','Getting stronger on my tummy','Your baby may only manage a minute or two on their tummy at first. That is still useful. Short, supervised floor moments help them practise lifting, turning and settling into their body, while building the neck, shoulder and back strength that later supports rolling and reaching.','for_your_child','cat_tummy_time_books','A soft tummy-time book','Tummy Time Books',4,'A soft fold-out or crinkle book can sit in front of your baby during supervised floor play. It gives them something to look towards, hear and touch, while you talk through what they are noticing. Keep it short, gentle and led by what your baby seems ready for.','for_your_child'),
  ('1-3m','1–3 months',1,3,true,'ent_cluster_kicks_wriggles','I’m starting to wriggle',5,true,'ent_need_first_grasps','Starting to wriggle','Your baby may kick, stretch, arch or wriggle when they are awake and comfortable. Safe floor time gives those little movements room to happen. It helps them notice their body, practise early control and build confidence before bigger movement arrives.','for_your_child','cat_kicky_floor_play','Kicky floor time','Kicky Floor Play',1,'Your baby may be stretching and kicking more strongly by the week. A low, clear play space lets them move both arms and legs freely, while you stay close and notice the little body-control experiments starting to appear. Keep it short, gentle and led by what your baby seems ready for.','for_your_child'),
  ('1-3m','1–3 months',1,3,true,'ent_cluster_kicks_wriggles','I’m starting to wriggle',5,true,'ent_need_visual_tracking','Starting to wriggle','Your baby may kick, stretch, arch or wriggle when they are awake and comfortable. Safe floor time gives those little movements room to happen. It helps them notice their body, practise early control and build confidence before bigger movement arrives.','for_your_child','cat_play_gym_hanging_toys','A simple play gym or hanging toys','Play Gym Hanging Toys',2,'A simple play gym can support short back-lying awake moments: looking up, kicking, swiping and beginning to notice what happens when their body moves. Keep it low-pressure and avoid leaving toys where baby sleeps. Keep it short, gentle and led by what your baby seems ready for.','for_your_child'),
  ('1-3m','1–3 months',1,3,true,'ent_cluster_kicks_wriggles','I’m starting to wriggle',5,true,'ent_need_tummy_head_control','Starting to wriggle','Your baby may kick, stretch, arch or wriggle when they are awake and comfortable. Safe floor time gives those little movements room to happen. It helps them notice their body, practise early control and build confidence before bigger movement arrives.','for_your_child','cat_safe_floor_space','A clear low floor space','Safe Floor Space',3,'The safest place for early movement practice is low and close to you. A clear patch of floor helps you avoid raised-surface risks as your baby gets stronger, wrigglier and more surprising in how quickly they can shift position. Keep it short, gentle and led by what your baby seems ready for.','for_your_child'),
  ('1-3m','1–3 months',1,3,true,'ent_cluster_kicks_wriggles','I’m starting to wriggle',5,true,'ent_need_tummy_head_control','Starting to wriggle','Your baby may kick, stretch, arch or wriggle when they are awake and comfortable. Safe floor time gives those little movements room to happen. It helps them notice their body, practise early control and build confidence before bigger movement arrives.','for_your_child','cat_supported_side_lying_play','Side-lying pauses and turns','Supported Side Lying Play',4,'Some babies start tipping or resting onto their side near this stage. Short, supervised side-lying pauses can help them feel a different body position, but the aim is gentle variety, not pushing rolling before they are ready. Keep it short, gentle and led by what your baby seems ready for.','for_your_child'),
  ('1-3m','1–3 months',1,3,true,'ent_cluster_first_grasps','My hands are waking up',6,true,'ent_need_first_grasps','Hands waking up','Your baby’s hands may be opening more often, brushing objects, watching fingers or holding a soft toy for a moment. These tiny discoveries help them connect sight, touch and movement. Simple graspable textures make hand play feel interesting without needing lots of stimulation.','for_your_child','cat_reach_grab_toys','Reach-and-grab toys','Reach Grab Toys',1,'Your baby’s hands may be opening more, with swipes and accidental touches starting to appear. A simple reach-and-grab toy lets them practise looking, moving an arm and feeling a response, even before grasping is reliable. Keep it short, gentle and led by what your baby seems ready for.','for_your_child'),
  ('1-3m','1–3 months',1,3,true,'ent_cluster_first_grasps','My hands are waking up',6,true,'ent_need_first_grasps','Hands waking up','Your baby’s hands may be opening more often, brushing objects, watching fingers or holding a soft toy for a moment. These tiny discoveries help them connect sight, touch and movement. Simple graspable textures make hand play feel interesting without needing lots of stimulation.','for_your_child','cat_soft_rattle_ring','A soft rattle or grasp ring','Soft Rattle Ring',2,'A soft rattle or grasp ring can make an accidental hand movement feel interesting. The sound or texture gives instant feedback, helping your baby begin to connect their hand, the object and what happens next. Keep it short, gentle and led by what your baby seems ready for.','for_your_child'),
  ('1-3m','1–3 months',1,3,true,'ent_cluster_first_grasps','My hands are waking up',6,true,'ent_need_first_grasps','Hands waking up','Your baby’s hands may be opening more often, brushing objects, watching fingers or holding a soft toy for a moment. These tiny discoveries help them connect sight, touch and movement. Simple graspable textures make hand play feel interesting without needing lots of stimulation.','for_your_child','cat_texture_cards_books','Soft textures to stroke and touch','Texture Cards Books',3,'Soft cloth, crinkle pages or simple texture cards give your baby something gentle to brush, scrunch or accidentally grab. At this stage, the value is in noticing touch and sound, not doing anything neatly. Keep it short, gentle and led by what your baby seems ready for.','for_your_child'),
  ('1-3m','1–3 months',1,3,true,'ent_cluster_first_grasps','My hands are waking up',6,true,'ent_need_first_grasps','Hands waking up','Your baby’s hands may be opening more often, brushing objects, watching fingers or holding a soft toy for a moment. These tiny discoveries help them connect sight, touch and movement. Simple graspable textures make hand play feel interesting without needing lots of stimulation.','for_your_child','cat_cleanable_sensory_toys','Easy-clean sensory toys','Cleanable Sensory Toys',4,'As hands and mouths become busier, easy-clean toys make repeated play less stressful. Choose simple textures, secure parts and materials you can wipe or wash, because hygiene starts to matter more as everything heads towards the mouth. Keep it short, gentle and led by what your baby seems ready for.','for_your_child'),
  ('1-3m','1–3 months',1,3,true,'ent_cluster_first_grasps','My hands are waking up',6,true,'ent_need_first_grasps','Hands waking up','Your baby’s hands may be opening more often, brushing objects, watching fingers or holding a soft toy for a moment. These tiny discoveries help them connect sight, touch and movement. Simple graspable textures make hand play feel interesting without needing lots of stimulation.','for_your_child','cat_teethers','Chew-safe toys and early teethers','Teethers',5,'Some babies start bringing hands and safe objects towards their mouth near the top of this band. A clean, age-suitable teether or chew-safe toy can give that exploring a safer outlet, but it is an edge-of-stage idea rather than a must-have for every baby.','for_your_child'),
  ('1-3m','1–3 months',1,3,true,'ent_cluster_calm_crying_settling','Help me settle and reconnect',7,true,'ent_need_crying_settling','Crying, comfort and little resets','Some days, your baby may cry, fuss or need help switching off. Gentle resets, cuddles, short walks and simple notes can help you spot patterns without turning it into a test. The aim is a calmer rhythm for both of you, not perfect settling.','for_both','cat_white_noise_soother','Gentle white noise or sound reset','White Noise Soother',1,'White noise is not a cure for crying, but a gentle background sound can sometimes help with a reset when your baby is tired, windy or overstimulated. Keep it low, distant and part of a calm response, not a constant soundtrack.','for_both'),
  ('1-3m','1–3 months',1,3,true,'ent_cluster_calm_crying_settling','Help me settle and reconnect',7,true,'ent_need_crying_settling','Crying, comfort and little resets','Some days, your baby may cry, fuss or need help switching off. Gentle resets, cuddles, short walks and simple notes can help you spot patterns without turning it into a test. The aim is a calmer rhythm for both of you, not perfect settling.','for_both','cat_pram_walk_reset','A pram walk reset','Pram Walk Reset',2,'A short pram walk can reset a difficult stretch of the day. Your baby gets movement, light and a new soundscape, while you get a small change of scene. It is useful because it is simple, not because it solves everything.','for_both'),
  ('1-3m','1–3 months',1,3,true,'ent_cluster_calm_crying_settling','Help me settle and reconnect',7,true,'ent_need_crying_settling','Crying, comfort and little resets','Some days, your baby may cry, fuss or need help switching off. Gentle resets, cuddles, short walks and simple notes can help you spot patterns without turning it into a test. The aim is a calmer rhythm for both of you, not perfect settling.','for_both','cat_soft_carrier_sling','A safe sling or carrier cuddle','Soft Carrier Sling',3,'Some unsettled babies calm when they are close to your body and voice. A safe, correctly fitted sling or carrier can help with cuddly resets and short household moments, as long as airway, position and temperature are carefully checked. Keep the setup simple and follow trusted safety guidance.','for_both'),
  ('1-3m','1–3 months',1,3,true,'ent_cluster_calm_crying_settling','Help me settle and reconnect',7,true,'ent_need_crying_settling','Crying, comfort and little resets','Some days, your baby may cry, fuss or need help switching off. Gentle resets, cuddles, short walks and simple notes can help you spot patterns without turning it into a test. The aim is a calmer rhythm for both of you, not perfect settling.','for_both','cat_settling_routine_notes','A simple settling notes routine','Settling Routine Notes',4,'When days blur together, a few notes on feeds, sleep, crying or what helped can make you feel less lost. The aim is not to force a routine, but to notice patterns and have something clear to share if you ask for support.','for_both'),
  ('1-3m','1–3 months',1,3,true,'ent_cluster_feeding_clean_kit','Keep feeds calm and clean',8,true,'ent_need_feeding_rhythm','Calm feeds and clean kit','Feeds can feel constant at this age, with cues, winding, leaking, bottles or breastfeeding comfort all happening at once. A small, calm setup helps you respond more easily and keep kit clean, whether you are feeding at home, overnight or out for a short trip.','for_you','cat_responsive_feeding_support','Responsive feeding cues','Responsive Feeding Support',1,'Early feeds can feel constant. Watching for cues like restlessness, rooting, murmuring or sucking hands can make feeding feel a little calmer because you are responding before your baby is fully upset. Keep the setup simple and follow trusted safety guidance.','for_you'),
  ('1-3m','1–3 months',1,3,true,'ent_cluster_feeding_clean_kit','Keep feeds calm and clean',8,true,'ent_need_feeding_rhythm','Calm feeds and clean kit','Feeds can feel constant at this age, with cues, winding, leaking, bottles or breastfeeding comfort all happening at once. A small, calm setup helps you respond more easily and keep kit clean, whether you are feeding at home, overnight or out for a short trip.','for_you','cat_burp_cloths_muslins','Muslins and burp cloths','Burp Cloths Muslins',2,'Tiny babies produce a surprising amount of milk dribble, spit-up and nappy-change mess. Muslins and burp cloths are not developmental toys, but they make the repeated feed, wind, wipe and reset loop easier to manage. Keep the setup simple and follow trusted safety guidance.','for_you'),
  ('1-3m','1–3 months',1,3,true,'ent_cluster_feeding_clean_kit','Keep feeds calm and clean',8,true,'ent_need_feeding_rhythm','Calm feeds and clean kit','Feeds can feel constant at this age, with cues, winding, leaking, bottles or breastfeeding comfort all happening at once. A small, calm setup helps you respond more easily and keep kit clean, whether you are feeding at home, overnight or out for a short trip.','for_you','cat_bottle_sterilising_kit','Bottle sterilising kit','Bottle Sterilising Kit',3,'If bottles are part of your routine, clean kit matters every day. Sterilising bottles, teats and feeding equipment reduces infection risk while your baby’s immune system is still developing, and keeps late-night feeds less chaotic. Keep the setup simple and follow trusted safety guidance.','for_you'),
  ('1-3m','1–3 months',1,3,true,'ent_cluster_feeding_clean_kit','Keep feeds calm and clean',8,true,'ent_need_feeding_rhythm','Calm feeds and clean kit','Feeds can feel constant at this age, with cues, winding, leaking, bottles or breastfeeding comfort all happening at once. A small, calm setup helps you respond more easily and keep kit clean, whether you are feeding at home, overnight or out for a short trip.','for_you','cat_breastfeeding_comfort_supplies','Breastfeeding comfort supplies','Breastfeeding Comfort Supplies',4,'A few practical supplies, such as breast pads, a water bottle, comfortable setup or support contact, can make frequent feeds feel less punishing. The important part is not buying more, it is making support and comfort easier to reach. Keep the setup simple and follow trusted safety guidance.','for_you'),
  ('1-3m','1–3 months',1,3,true,'ent_cluster_feeding_clean_kit','Keep feeds calm and clean',8,true,'ent_need_feeding_rhythm','Calm feeds and clean kit','Feeds can feel constant at this age, with cues, winding, leaking, bottles or breastfeeding comfort all happening at once. A small, calm setup helps you respond more easily and keep kit clean, whether you are feeding at home, overnight or out for a short trip.','for_you','cat_milk_storage_and_labels','Milk storage and labels','Milk Storage And Labels',5,'If expressing is part of your routine, simple storage bags or containers and clear labels can reduce confusion. This is mainly a practical parent tool, helping you track dates and use milk safely without relying on memory during tired weeks.','for_you'),
  ('1-3m','1–3 months',1,3,true,'ent_cluster_safe_sleep_setup','Make sleep feel safe',9,true,'ent_need_safe_sleep_setup','Safer sleep made simple','Safer sleep is one place where simple rules really help. A clear, firm, flat space with the right bedding choices can make naps and nights feel less confusing. This cluster keeps the focus on calm, practical setup rather than extra sleep products.','for_you','cat_safe_sleep_continuity','Safe sleep check-in','Safe Sleep Continuity',1,'A safe sleep check is one of the highest-value parent jobs in this band. Back sleeping, a clear cot or Moses basket, same-room sleep and no loose extras matter more than any gadget promising better sleep. Keep the setup simple and follow trusted safety guidance.','for_you'),
  ('1-3m','1–3 months',1,3,true,'ent_cluster_safe_sleep_setup','Make sleep feel safe',9,true,'ent_need_safe_sleep_setup','Safer sleep made simple','Safer sleep is one place where simple rules really help. A clear, firm, flat space with the right bedding choices can make naps and nights feel less confusing. This cluster keeps the focus on calm, practical setup rather than extra sleep products.','for_you','cat_firm_flat_mattress','A firm, flat, waterproof mattress','Firm Flat Mattress',2,'A firm, flat, waterproof mattress is a quiet safety essential. It helps keep the sleep surface clear and appropriate, and the NHS advises buying new if possible or only reusing from your own clean, dry, smoke-free home. Keep the setup simple and follow trusted safety guidance.','for_you'),
  ('1-3m','1–3 months',1,3,true,'ent_cluster_safe_sleep_setup','Make sleep feel safe',9,true,'ent_need_safe_sleep_setup','Safer sleep made simple','Safer sleep is one place where simple rules really help. A clear, firm, flat space with the right bedding choices can make naps and nights feel less confusing. This cluster keeps the focus on calm, practical setup rather than extra sleep products.','for_you','cat_room_thermometer','Room thermometer','Room Thermometer',3,'A room thermometer helps you check whether the room is in the safer sleep temperature range, rather than guessing by how you feel. It pairs with clothing and sleeping-bag choices, especially as seasons change. Keep the setup simple and follow trusted safety guidance.','for_you'),
  ('1-3m','1–3 months',1,3,true,'ent_cluster_safe_sleep_setup','Make sleep feel safe',9,true,'ent_need_safe_sleep_setup','Safer sleep made simple','Safer sleep is one place where simple rules really help. A clear, firm, flat space with the right bedding choices can make naps and nights feel less confusing. This cluster keeps the focus on calm, practical setup rather than extra sleep products.','for_you','cat_baby_sleeping_bag','A well-fitting baby sleeping bag','Baby Sleeping Bag',4,'A baby sleeping bag can help keep bedding simple, but fit and tog matter. The shoulders should fit well so baby cannot slip down inside, and the warmth should match the room temperature. Keep the setup simple and follow trusted safety guidance.','for_you'),
  ('1-3m','1–3 months',1,3,true,'ent_cluster_safe_sleep_setup','Make sleep feel safe',9,true,'ent_need_safe_sleep_setup','Safer sleep made simple','Safer sleep is one place where simple rules really help. A clear, firm, flat space with the right bedding choices can make naps and nights feel less confusing. This cluster keeps the focus on calm, practical setup rather than extra sleep products.','for_you','cat_clear_cot_check','Clear cot checks','Clear Cot Check',5,'A clear cot check is a small habit with big safety value. It helps you spot pillows, bumpers, soft toys, pods, nests, wedges or bulky bedding that can look helpful in a shop but should not be in baby’s sleep space.','for_you'),
  ('1-3m','1–3 months',1,3,true,'ent_cluster_health_first_trips','Keep first trips simpler',10,true,'ent_need_health_first_trips','First trips and check-ins','By 1 to 3 months, check-ups, jabs, nappy changes and first outings can all start to stack up. A few prepared basics make it easier to leave the house or handle a change quickly, while keeping safety jobs like car seats and small objects in view.','for_you','cat_red_book_vaccine_planning','Red Book and vaccine planning','Red Book Vaccine Planning',1,'The 6-week check and first vaccinations can arrive quickly while you are still in newborn fog. Keeping the Red Book, appointments and questions together helps you feel prepared, and gives you a useful record of growth, checks and immunisations. Keep the setup simple and follow trusted safety guidance.','for_you'),
  ('1-3m','1–3 months',1,3,true,'ent_cluster_health_first_trips','Keep first trips simpler',10,true,'ent_need_health_first_trips','First trips and check-ins','By 1 to 3 months, check-ups, jabs, nappy changes and first outings can all start to stack up. A few prepared basics make it easier to leave the house or handle a change quickly, while keeping safety jobs like car seats and small objects in view.','for_you','cat_rear_facing_car_seat','Rear-facing infant car seat','Rear Facing Car Seat',2,'A suitable rear-facing infant car seat is one of the clearest safety-critical purchases. UK rules require height-based seats to stay rear-facing until your child is over 15 months, so fit, approval and history matter from the start. Keep the setup simple and follow trusted safety guidance.','for_you'),
  ('1-3m','1–3 months',1,3,true,'ent_cluster_health_first_trips','Keep first trips simpler',10,true,'ent_need_health_first_trips','First trips and check-ins','By 1 to 3 months, check-ups, jabs, nappy changes and first outings can all start to stack up. A few prepared basics make it easier to leave the house or handle a change quickly, while keeping safety jobs like car seats and small objects in view.','for_you','cat_nappy_change_station','Nappy change station','Nappy Change Station',3,'A simple change station means the mat, wipes or cotton wool, clean nappy, bag, drying cloth and barrier cream are within reach before you start. That matters when changes are frequent and baby is getting wrigglier. Keep the setup simple and follow trusted safety guidance.','for_you'),
  ('1-3m','1–3 months',1,3,true,'ent_cluster_health_first_trips','Keep first trips simpler',10,true,'ent_need_health_first_trips','First trips and check-ins','By 1 to 3 months, check-ups, jabs, nappy changes and first outings can all start to stack up. A few prepared basics make it easier to leave the house or handle a change quickly, while keeping safety jobs like car seats and small objects in view.','for_you','cat_small_object_sweep','Small-object safety sweep','Small Object Sweep',4,'Your baby may not be crawling yet, but hands and mouths become busier fast. A simple sweep for tiny loose parts, cords, old toy pieces and unsafe older-sibling items keeps the floor-play area ready before movement suddenly jumps forward. Keep the setup simple and follow trusted safety guidance.','for_you'),
  ('1-3m','1–3 months',1,3,true,'ent_cluster_health_first_trips','Keep first trips simpler',10,true,'ent_need_health_first_trips','First trips and check-ins','By 1 to 3 months, check-ups, jabs, nappy changes and first outings can all start to stack up. A few prepared basics make it easier to leave the house or handle a change quickly, while keeping safety jobs like car seats and small objects in view.','for_you','cat_button_battery_check','Button battery checks','Button Battery Check',5,'Button batteries are not a play category, but they matter in homes full of gadgets, musical toys and older-sibling items. A quick check for secure compartments and loose batteries helps keep the play area safer as reaching and mouthing increase.','for_you'),
  ('4-6m','4–6 months',4,6,true,'ent_cluster_4_6_floor_strength','The floor is my little gym',1,true,'ent_need_4_6_floor_strength','Floor strength and rolling practice','Wriggling on the floor, lifting for a toy or rolling onto a side can be hard work. This cluster gives your baby safe, supervised reasons to look, reach, push and rest, so floor time feels like a small discovery moment rather than a formal exercise.','for_your_child','cat_tummy_time_mat','A clean floor-play mat','Tummy Time Mat',1,'A clean, firm floor space makes short tummy-time sessions easier to repeat. Your baby can lift, turn, rest and try again while staying low to the ground. It gives you one simple place for awake play without turning every session into a big setup.','for_your_child'),
  ('4-6m','4–6 months',4,6,true,'ent_cluster_4_6_floor_strength','The floor is my little gym',1,true,'ent_need_4_6_floor_strength','Floor strength and rolling practice','Wriggling on the floor, lifting for a toy or rolling onto a side can be hard work. This cluster gives your baby safe, supervised reasons to look, reach, push and rest, so floor time feels like a small discovery moment rather than a formal exercise.','for_your_child','cat_tummy_time_wobbler','Wobbly tummy-time toys','Tummy Time Wobbler',2,'A small wobbly toy, placed just in front of your baby, can make tummy time more interesting. The tiny movement gives them something to look towards, bat at or follow, while you keep the session short, close and responsive to their cues.','for_your_child'),
  ('4-6m','4–6 months',4,6,true,'ent_cluster_4_6_floor_strength','The floor is my little gym',1,true,'ent_need_4_6_floor_strength','Floor strength and rolling practice','Wriggling on the floor, lifting for a toy or rolling onto a side can be hard work. This cluster gives your baby safe, supervised reasons to look, reach, push and rest, so floor time feels like a small discovery moment rather than a formal exercise.','for_your_child','cat_baby_safe_mirror','A baby-safe mirror','Baby Safe Mirror',3,'A mirror can hold your baby’s attention for a few extra moments on the floor. They may not understand the reflection yet, but the face, movement and your voice nearby can invite looking, lifting and shared smiles during supervised play.','for_your_child'),
  ('4-6m','4–6 months',4,6,true,'ent_cluster_4_6_floor_strength','The floor is my little gym',1,true,'ent_need_4_6_floor_strength','Floor strength and rolling practice','Wriggling on the floor, lifting for a toy or rolling onto a side can be hard work. This cluster gives your baby safe, supervised reasons to look, reach, push and rest, so floor time feels like a small discovery moment rather than a formal exercise.','for_your_child','cat_soft_graspable_balls','Soft balls to watch, hold and roll','Soft Graspable Balls',4,'A soft ball can turn ordinary floor time into a little chase. You can roll it slowly, pause, let your baby watch or reach, then bring it back again. That simple loop gives movement, attention and hand control something playful to work with.','for_your_child'),
  ('4-6m','4–6 months',4,6,true,'ent_cluster_4_6_hands','My hands can do more now',2,true,'ent_need_4_6_hand_control','Reaching, grasping and early hand control','Your baby may be swiping, holding, chewing and trying to bring interesting things closer. These small hand moments can become satisfying play when objects are light, safe and easy to grip, helping your baby connect what they see, feel and move.','for_your_child','cat_reach_grab_toys','Reach-and-grab toys','Reach Grab Toys',1,'A toy just within reach can become a tiny challenge. Your baby may stare, swipe, grab, drop and try again. That repeated effort helps connect looking with hand movement, while keeping the play simple enough for short awake windows while you stay close.','for_your_child'),
  ('4-6m','4–6 months',4,6,true,'ent_cluster_4_6_hands','My hands can do more now',2,true,'ent_need_4_6_hand_control','Reaching, grasping and early hand control','Your baby may be swiping, holding, chewing and trying to bring interesting things closer. These small hand moments can become satisfying play when objects are light, safe and easy to grip, helping your baby connect what they see, feel and move.','for_your_child','cat_hand_transfer_toys','Toys to pass between hands','Hand Transfer Toys',2,'Near the top of this band, some babies start turning, twisting or passing objects from one hand to the other. A light, easy-to-hold toy gives them space to practise that back-and-forth without needing a complicated activity.','for_your_child'),
  ('4-6m','4–6 months',4,6,true,'ent_cluster_4_6_hands','My hands can do more now',2,true,'ent_need_4_6_hand_control','Reaching, grasping and early hand control','Your baby may be swiping, holding, chewing and trying to bring interesting things closer. These small hand moments can become satisfying play when objects are light, safe and easy to grip, helping your baby connect what they see, feel and move.','for_your_child','cat_sound_cylinders_shakers','Soft rattles and shakers','Sound Cylinders Shakers',3,'A soft rattle can make a hand movement feel exciting. When your baby shakes, drops or bangs it and hears a sound, they begin to notice that their own movement can change what happens around them while you stay close.','for_your_child'),
  ('4-6m','4–6 months',4,6,true,'ent_cluster_4_6_hands','My hands can do more now',2,true,'ent_need_4_6_hand_control','Reaching, grasping and early hand control','Your baby may be swiping, holding, chewing and trying to bring interesting things closer. These small hand moments can become satisfying play when objects are light, safe and easy to grip, helping your baby connect what they see, feel and move.','for_your_child','cat_cleanable_sensory_toys','Easy-clean sensory toys','Cleanable Sensory Toys',4,'As hands and mouths get busier, wipeable or washable toys make repeated play less stressful. Different textures can invite grabbing, squeezing and mouthing, while easy cleaning helps parents keep the stage practical rather than constantly worrying about mess while you stay close.','for_your_child'),
  ('4-6m','4–6 months',4,6,true,'cluster_mouth_sensory','Everything goes in my mouth',3,true,'ent_need_4_6_mouth_sensory','Mouthing and sensory exploration','Hands, toys and safe textures often head straight to your baby’s mouth now. That can be normal exploring, and near six months it may overlap with teething. This cluster helps parents choose simple, washable, age-suitable objects while keeping tiny hazards away.','for_your_child','cat_teethers','Teethers and chew-safe toys','Teethers',1,'If your baby is chewing everything they can reach, an age-suitable teether can give that urge somewhere safer to go. It can help during ordinary mouthing and, near six months, may also be useful if teething signs start to appear.','for_your_child'),
  ('4-6m','4–6 months',4,6,true,'cluster_mouth_sensory','Everything goes in my mouth',3,true,'ent_need_4_6_mouth_sensory','Mouthing and sensory exploration','Hands, toys and safe textures often head straight to your baby’s mouth now. That can be normal exploring, and near six months it may overlap with teething. This cluster helps parents choose simple, washable, age-suitable objects while keeping tiny hazards away.','for_your_child','cat_texture_cards_books','Touch-and-feel cards or books','Texture Cards Books',2,'A soft texture page or card gives your baby something to brush, grab, crinkle or mouth while you name what they notice. The value is not reading neatly, it is the shared moment of touch, sound and attention while you stay close.','for_your_child'),
  ('4-6m','4–6 months',4,6,true,'cluster_mouth_sensory','Everything goes in my mouth',3,true,'ent_need_4_6_mouth_sensory','Mouthing and sensory exploration','Hands, toys and safe textures often head straight to your baby’s mouth now. That can be normal exploring, and near six months it may overlap with teething. This cluster helps parents choose simple, washable, age-suitable objects while keeping tiny hazards away.','for_your_child','cat_mouth_safe_grasp_rings','Mouth-safe grasp rings','Mouth Safe Grasp Rings',3,'A simple grasp ring can be easy for little hands to catch, hold, drop and bring back to the mouth. That makes it useful for both hand practice and safe sensory exploring, especially when everything is being tested by touch and taste.','for_your_child'),
  ('4-6m','4–6 months',4,6,true,'cluster_mouth_sensory','Everything goes in my mouth',3,true,'ent_need_4_6_mouth_sensory','Mouthing and sensory exploration','Hands, toys and safe textures often head straight to your baby’s mouth now. That can be normal exploring, and near six months it may overlap with teething. This cluster helps parents choose simple, washable, age-suitable objects while keeping tiny hazards away.','for_your_child','cat_safe_household_objects','Safe everyday-object play','Safe Household Objects',4,'A clean cloth, large silicone spoon or empty tub can be fascinating when it is safe and supervised. Everyday objects give your baby new textures, shapes and sounds to explore, while helping parents avoid buying a new toy for every tiny stage.','for_your_child'),
  ('4-6m','4–6 months',4,6,true,'ent_cluster_4_6_faces_sounds','Talk to me',4,true,'ent_need_4_6_social_communication','Faces, sounds and back-and-forth play','A squeal, a smile, a raspberry or a look back at you can be the start of a tiny conversation. This cluster gives parents easy ways to pause, copy, sing, show faces and read together, so communication feels warm and playful before words arrive.','for_your_child','cat_board_books','Chunky board books','Board Books',1,'A short board book can become a familiar little ritual: look, pause, name one thing, then wait for your baby’s face or sound. The pages matter less than the shared attention and your voice doing the same thing again while you stay close.','for_your_child'),
  ('4-6m','4–6 months',4,6,true,'ent_cluster_4_6_faces_sounds','Talk to me',4,true,'ent_need_4_6_social_communication','Faces, sounds and back-and-forth play','A squeal, a smile, a raspberry or a look back at you can be the start of a tiny conversation. This cluster gives parents easy ways to pause, copy, sing, show faces and read together, so communication feels warm and playful before words arrive.','for_your_child','cat_songs_action_games','Songs, pauses and silly sounds','Songs Action Games',2,'A song with pauses gives your baby a chance to join in with a look, wriggle, squeal or raspberry. Copying their sound and waiting can make a tiny back-and-forth game, even before clear babbling arrives while you stay close.','for_your_child'),
  ('4-6m','4–6 months',4,6,true,'ent_cluster_4_6_faces_sounds','Talk to me',4,true,'ent_need_4_6_social_communication','Faces, sounds and back-and-forth play','A squeal, a smile, a raspberry or a look back at you can be the start of a tiny conversation. This cluster gives parents easy ways to pause, copy, sing, show faces and read together, so communication feels warm and playful before words arrive.','for_your_child','cat_family_faces_cards','Family photo cards','Family Faces Cards',3,'Simple family photos can give your baby familiar faces to notice. You can name one person, wait, smile and repeat. It is a small way to connect recognition, attention and language without needing a busy toy or screen while you stay close.','for_your_child'),
  ('4-6m','4–6 months',4,6,true,'ent_cluster_4_6_faces_sounds','Talk to me',4,true,'ent_need_4_6_social_communication','Faces, sounds and back-and-forth play','A squeal, a smile, a raspberry or a look back at you can be the start of a tiny conversation. This cluster gives parents easy ways to pause, copy, sing, show faces and read together, so communication feels warm and playful before words arrive.','for_your_child','cat_feelings_faces_books','Baby faces and feelings books','Feelings Faces Books',4,'Books with baby faces, smiles or everyday expressions give you something concrete to point to and name. Your baby will not understand feelings neatly yet, but faces, voice and repetition make this a warm shared-attention moment while you stay close.','for_your_child'),
  ('4-6m','4–6 months',4,6,true,'ent_cluster_4_6_cause_effect','I can make things happen',5,true,'ent_need_4_6_cause_effect','Cause-and-effect sensory play','A shake, kick, crinkle or spin can suddenly feel fascinating because your baby is starting to connect movement with a response. This cluster turns simple sensory feedback into playful experiments, while keeping the objects sturdy, safe and easy to supervise.','for_your_child','cat_crinkle_cloth_toys','Crinkle cloths and soft sound toys','Crinkle Cloth Toys',1,'A soft crinkle toy can turn a small squeeze or swipe into sound. That little response helps your baby notice the connection between their hand and what happens next, while keeping the play soft enough for floor or lap time.','for_your_child'),
  ('4-6m','4–6 months',4,6,true,'ent_cluster_4_6_cause_effect','I can make things happen',5,true,'ent_need_4_6_cause_effect','Cause-and-effect sensory play','A shake, kick, crinkle or spin can suddenly feel fascinating because your baby is starting to connect movement with a response. This cluster turns simple sensory feedback into playful experiments, while keeping the objects sturdy, safe and easy to supervise.','for_your_child','cat_kick_play_socks','Kick-and-discover socks','Kick Play Socks',2,'If your baby is finding their feet, soft play socks or gentle ankle rattles can make kicks and leg movements more noticeable. It is not about training movement, just giving your baby another small thing to feel, hear and discover.','for_your_child'),
  ('4-6m','4–6 months',4,6,true,'ent_cluster_4_6_cause_effect','I can make things happen',5,true,'ent_need_4_6_cause_effect','Cause-and-effect sensory play','A shake, kick, crinkle or spin can suddenly feel fascinating because your baby is starting to connect movement with a response. This cluster turns simple sensory feedback into playful experiments, while keeping the objects sturdy, safe and easy to supervise.','for_your_child','cat_spinner_reach_toys','Simple spinners for reaching','Spinner Reach Toys',3,'A simple spinner can give your baby an obvious result when they reach, tap or push. The movement keeps attention for a moment, while the action stays small and manageable for a baby who is still learning how hands work.','for_your_child'),
  ('4-6m','4–6 months',4,6,true,'ent_cluster_4_6_cause_effect','I can make things happen',5,true,'ent_need_4_6_cause_effect','Cause-and-effect sensory play','A shake, kick, crinkle or spin can suddenly feel fascinating because your baby is starting to connect movement with a response. This cluster turns simple sensory feedback into playful experiments, while keeping the objects sturdy, safe and easy to supervise.','for_your_child','cat_pull_out_tissue_box','Pull-out box toys','Pull Out Tissue Box',4,'Pulling a soft cloth from a box, seeing another appear and trying again can feel wonderfully satisfying. It gives your baby a first taste of cause and effect, containment and texture without needing a complicated toy while you stay close.','for_your_child'),
  ('4-6m','4–6 months',4,6,true,'ent_cluster_4_6_body_world','I’m finding my body',6,true,'ent_need_4_6_body_awareness','Body awareness and first little words','Your baby may be staring at their hands, grabbing feet or lighting up at a familiar face. This cluster makes those ordinary moments easier to notice and name, using mirrors, body books and simple games that help your baby connect movement, touch and words.','for_your_child','cat_parts_of_me_books','Body-part board books','Parts Of Me Books',1,'A body-part book gives you easy words for what your baby is already finding: hands, feet, tummy, face. Pointing, naming and pausing makes the moment feel playful, even if your baby mostly wants to chew the page while you stay close.','for_your_child'),
  ('4-6m','4–6 months',4,6,true,'ent_cluster_4_6_body_world','I’m finding my body',6,true,'ent_need_4_6_body_awareness','Body awareness and first little words','Your baby may be staring at their hands, grabbing feet or lighting up at a familiar face. This cluster makes those ordinary moments easier to notice and name, using mirrors, body books and simple games that help your baby connect movement, touch and words.','for_your_child','cat_feet_discovery_games','Foot-finding floor games','Feet Discovery Games',2,'When your baby reaches for their toes, you can turn it into a gentle naming game: feet, toes, kick, again. The movement is already happening, and your voice helps make it a shared moment of body awareness while you stay close.','for_your_child'),
  ('4-6m','4–6 months',4,6,true,'ent_cluster_4_6_body_world','I’m finding my body',6,true,'ent_need_4_6_body_awareness','Body awareness and first little words','Your baby may be staring at their hands, grabbing feet or lighting up at a familiar face. This cluster makes those ordinary moments easier to notice and name, using mirrors, body books and simple games that help your baby connect movement, touch and words.','for_your_child','cat_mirror_body_play','Mirror-and-body play','Mirror Body Play',3,'A baby-safe mirror can become more than a looking toy when you name what appears: eyes, smile, hands, baby. Your baby may simply watch or grin, but that small pause builds shared attention around body and face words while you stay close.','for_your_child'),
  ('4-6m','4–6 months',4,6,true,'ent_cluster_4_6_body_world','I’m finding my body',6,true,'ent_need_4_6_body_awareness','Body awareness and first little words','Your baby may be staring at their hands, grabbing feet or lighting up at a familiar face. This cluster makes those ordinary moments easier to notice and name, using mirrors, body books and simple games that help your baby connect movement, touch and words.','for_your_child','cat_soft_sensory_balls','Soft sensory balls','Soft Sensory Balls',4,'A soft textured ball can be squeezed, rolled, mouthed or held against little feet. It gives your baby another way to feel shape, pressure and movement, while you keep the language simple and the game close while you stay close.','for_your_child'),
  ('4-6m','4–6 months',4,6,true,'cluster_first_foods','First tastes are getting close',7,true,'ent_need_4_6_first_foods','First foods readiness','Near six months, first tastes may be getting closer, but the useful job is readiness, not rushing. This cluster helps parents spot the real signs, set up safe seating and keep early meals calm, messy and responsive to their baby’s cues.','for_both','cat_highchair','A supportive highchair','Highchair',1,'When first foods begin, upright seating helps your baby stay steady while you stay close. A supportive highchair or feeding seat is not about neat eating, it is about making those tiny first tastes safer, calmer and easier to manage.','for_both'),
  ('4-6m','4–6 months',4,6,true,'cluster_first_foods','First tastes are getting close',7,true,'ent_need_4_6_first_foods','First foods readiness','Near six months, first tastes may be getting closer, but the useful job is readiness, not rushing. This cluster helps parents spot the real signs, set up safe seating and keep early meals calm, messy and responsive to their baby’s cues.','for_both','cat_open_cup','An open or free-flow cup','Open Cup',2,'A small open or free-flow cup can be introduced with meals from around six months. Expect spills, chewing and confusion at first. The useful part is the repeated practice: holding, sipping and learning a new mouth movement slowly while you stay close.','for_both'),
  ('4-6m','4–6 months',4,6,true,'cluster_first_foods','First tastes are getting close',7,true,'ent_need_4_6_first_foods','First foods readiness','Near six months, first tastes may be getting closer, but the useful job is readiness, not rushing. This cluster helps parents spot the real signs, set up safe seating and keep early meals calm, messy and responsive to their baby’s cues.','for_both','cat_first_spoons_bowls','First spoons and bowls','First Spoons Bowls',3,'A small spoon and simple bowl can help your baby touch, hold, wave and sometimes taste food. If they turn away or close their mouth, that is useful communication too. The aim is relaxed practice, not finishing a portion while you stay close.','for_both'),
  ('4-6m','4–6 months',4,6,true,'cluster_first_foods','First tastes are getting close',7,true,'ent_need_4_6_first_foods','First foods readiness','Near six months, first tastes may be getting closer, but the useful job is readiness, not rushing. This cluster helps parents spot the real signs, set up safe seating and keep early meals calm, messy and responsive to their baby’s cues.','for_both','cat_weaning_bibs_mat','Bibs and splash mats','Weaning Bibs Mat',4,'Early feeding can mean food on hands, cheeks, chair and floor. Bibs and a splash mat do not teach feeding, but they make the mess easier to tolerate, so parents can let babies touch and explore without feeling every meal is a cleanup crisis.','for_both'),
  ('4-6m','4–6 months',4,6,true,'cluster_first_foods','First tastes are getting close',7,true,'ent_need_4_6_first_foods','First foods readiness','Near six months, first tastes may be getting closer, but the useful job is readiness, not rushing. This cluster helps parents spot the real signs, set up safe seating and keep early meals calm, messy and responsive to their baby’s cues.','for_both','cat_allergen_tracking','Food notes or allergen tracker','Allergen Tracking',5,'A few simple notes can help parents remember what was offered, when, and whether anything changed afterwards. It is especially useful when introducing common allergen foods one at a time, without turning early feeding into a spreadsheet obsession while you stay close.','for_both'),
  ('4-6m','4–6 months',4,6,true,'ent_cluster_4_6_safety','Keep this next stage safe',8,true,'ent_need_4_6_safety_setup','Safety checks for a busier baby','A baby who rolls, reaches and mouths more can change the home before anyone feels ready. This cluster keeps the parent job calm and practical: check sleep space, car-seat fit, tiny hazards and battery risks before the next jump in movement.','for_you','cat_safe_sleep_continuity','Safe sleep check-in','Safe Sleep Continuity',1,'This is still part of the first-six-month safer sleep window. A quick check of back sleeping, same-room sleep, room temperature and a clear cot can do more for safety than adding another sleep gadget while you stay close.','for_you'),
  ('4-6m','4–6 months',4,6,true,'ent_cluster_4_6_safety','Keep this next stage safe',8,true,'ent_need_4_6_safety_setup','Safety checks for a busier baby','A baby who rolls, reaches and mouths more can change the home before anyone feels ready. This cluster keeps the parent job calm and practical: check sleep space, car-seat fit, tiny hazards and battery risks before the next jump in movement.','for_you','cat_rear_facing_car_seat','Rear-facing car-seat check','Rear Facing Car Seat',2,'At 4-6 months, the question is usually fit and correct use, not turning forward. A quick check of approval label, harness position, seat limits and airbag guidance helps keep travel safe as your baby grows while you stay close.','for_you'),
  ('4-6m','4–6 months',4,6,true,'ent_cluster_4_6_safety','Keep this next stage safe',8,true,'ent_need_4_6_safety_setup','Safety checks for a busier baby','A baby who rolls, reaches and mouths more can change the home before anyone feels ready. This cluster keeps the parent job calm and practical: check sleep space, car-seat fit, tiny hazards and battery risks before the next jump in movement.','for_you','cat_small_object_sweep','Small-object safety sweep','Small Object Sweep',3,'Your baby may not be crawling yet, but reaching and mouthing can make the floor feel different overnight. A simple sweep for coins, old toy parts, beads and older-sibling pieces helps keep floor play safer while you stay close.','for_you'),
  ('4-6m','4–6 months',4,6,true,'ent_cluster_4_6_safety','Keep this next stage safe',8,true,'ent_need_4_6_safety_setup','Safety checks for a busier baby','A baby who rolls, reaches and mouths more can change the home before anyone feels ready. This cluster keeps the parent job calm and practical: check sleep space, car-seat fit, tiny hazards and battery risks before the next jump in movement.','for_you','cat_button_battery_check','Button battery check','Button Battery Check',4,'Musical toys, remotes, thermometers and greeting cards can hide button batteries. Checking that compartments are secure and loose batteries are out of reach is a small job with high safety value as hands and mouths get busier while you stay close.','for_you'),
  ('4-6m','4–6 months',4,6,true,'ent_cluster_4_6_safety','Keep this next stage safe',8,true,'ent_need_4_6_safety_setup','Safety checks for a busier baby','A baby who rolls, reaches and mouths more can change the home before anyone feels ready. This cluster keeps the parent job calm and practical: check sleep space, car-seat fit, tiny hazards and battery risks before the next jump in movement.','for_you','cat_clear_cot_check','Clear cot check','Clear Cot Check',5,'Soft toys, bumpers, nests and wedges can look helpful, but a clear sleep space is safer. A quick cot check is especially useful before rolling and reaching feel more active, when extra items can end up closer to baby’s face.','for_you'),
  ('9-12m','9–12 months',9,12,true,'ent_cluster_move','I’m getting ready to move',1,true,'ent_need_mobility','Ready to reach and move','Your baby may be sitting, crawling, reaching for toys, pulling up or cruising along furniture. This is a lovely window for safe floor space, steady surfaces and simple movement games that let them practise balance and confidence without rushing them toward walking.','for_both','cat_floor_zone','Clear floor space for moving','Floor Zone',1,'Clearing a safe patch of floor gives your baby a reason to reach, pivot, crawl or shuffle toward something interesting. A few soft, easy-to-grab objects just out of reach can turn ordinary floor time into calm movement practice. It is easy to repeat in short, supervised bursts.','for_both'),
  ('9-12m','9–12 months',9,12,true,'ent_cluster_move','I’m getting ready to move',1,true,'ent_need_mobility','Ready to reach and move','Your baby may be sitting, crawling, reaching for toys, pulling up or cruising along furniture. This is a lovely window for safe floor space, steady surfaces and simple movement games that let them practise balance and confidence without rushing them toward walking.','for_both','cat_cruising_furniture','Steady surfaces for pulling up','Cruising Furniture',2,'If your baby is starting to pull up, steady surfaces can give them a safe place to practise. The goal is not to hurry walking, but to make those wobbly standing moments calmer, more supported and easier to supervise. It is easy to repeat in short, supervised bursts.','for_both'),
  ('9-12m','9–12 months',9,12,true,'ent_cluster_move','I’m getting ready to move',1,true,'ent_need_mobility','Ready to reach and move','Your baby may be sitting, crawling, reaching for toys, pulling up or cruising along furniture. This is a lovely window for safe floor space, steady surfaces and simple movement games that let them practise balance and confidence without rushing them toward walking.','for_both','cat_push_pull_toys','Push-and-pull toys, when ready','Push Pull Toys',3,'Some babies near the end of this stage enjoy pushing, pulling or following a toy across the floor. If your baby is already steady enough, a stable push-and-pull toy can add a playful reason to move, without using a seated walker.','for_your_child'),
  ('9-12m','9–12 months',9,12,true,'ent_cluster_move','I’m getting ready to move',1,true,'ent_need_mobility','Ready to reach and move','Your baby may be sitting, crawling, reaching for toys, pulling up or cruising along furniture. This is a lovely window for safe floor space, steady surfaces and simple movement games that let them practise balance and confidence without rushing them toward walking.','for_both','cat_soft_graspable_balls','Soft balls to chase and roll','Soft Graspable Balls',4,'Rolling a soft ball away, passing it between you or watching it bounce gently can make movement feel playful. It gives your baby a clear thing to reach for, chase, hold, throw or pass, while keeping the game simple. It is easy to repeat in short, supervised bursts.','for_your_child'),
  ('9-12m','9–12 months',9,12,true,'ent_cluster_move','I’m getting ready to move',1,true,'ent_need_mobility','Ready to reach and move','Your baby may be sitting, crawling, reaching for toys, pulling up or cruising along furniture. This is a lovely window for safe floor space, steady surfaces and simple movement games that let them practise balance and confidence without rushing them toward walking.','for_both','cat_park_swings','Park trips and baby swings','Park Swings',5,'A short park trip can reset the day and give your baby new things to watch, hear and name. An age-suitable baby swing, used closely, can add gentle movement and shared smiles without needing another toy at home. It is easy to repeat in short, supervised bursts.','for_both'),
  ('9-12m','9–12 months',9,12,true,'ent_cluster_move','I’m getting ready to move',1,true,'ent_need_mobility','Ready to reach and move','Your baby may be sitting, crawling, reaching for toys, pulling up or cruising along furniture. This is a lovely window for safe floor space, steady surfaces and simple movement games that let them practise balance and confidence without rushing them toward walking.','for_both','cat_low_obstacle','Soft cushions and crawl-through games','Low Obstacle',6,'A cushion to move around or a low tunnel to crawl through can make floor play feel like an adventure. Keep it soft and simple so your baby can practise balance, reaching and body control while you stay close. It is easy to repeat in short, supervised bursts.','for_your_child'),
  ('9-12m','9–12 months',9,12,true,'ent_cluster_hands','My hands can do more now',2,true,'ent_need_pincer','Busy little hands','Your baby may be grabbing, banging, passing toys between hands, raking food or trying tiny finger-and-thumb movements. Everyday play with cups, baskets, chunky pieces and safe household objects can help them practise hand control, focus and early problem-solving in a way that feels like discovery.','for_your_child','cat_pincer_puzzle','Chunky peg and drop games','Pincer Puzzle',1,'Picking up a chunky peg, holding it, turning it and dropping it into place gives your baby a clear little task. That satisfying try-again loop can help build finger control, focus and early problem-solving. It is simple to repeat and easy to change up.','for_your_child'),
  ('9-12m','9–12 months',9,12,true,'ent_cluster_hands','My hands can do more now',2,true,'ent_need_bilateral','Busy little hands','Your baby may be grabbing, banging, passing toys between hands, raking food or trying tiny finger-and-thumb movements. Everyday play with cups, baskets, chunky pieces and safe household objects can help them practise hand control, focus and early problem-solving in a way that feels like discovery.','for_your_child','cat_stacking_nesting_cups','Stacking, nesting and filling cups','Stacking Nesting Cups',2,'Cups are wonderfully flexible at this age. Your baby can bang them, hide things inside, tip them out, stack them badly, knock them down and try again. Each small action helps with hand control, attention and cause-and-effect. It is simple to repeat and easy to change up.','for_your_child'),
  ('9-12m','9–12 months',9,12,true,'ent_cluster_hands','My hands can do more now',2,true,'ent_need_container','Busy little hands','Your baby may be grabbing, banging, passing toys between hands, raking food or trying tiny finger-and-thumb movements. Everyday play with cups, baskets, chunky pieces and safe household objects can help them practise hand control, focus and early problem-solving in a way that feels like discovery.','for_your_child','cat_container_basket','Treasure baskets and emptying games','Container Basket',3,'A basket of large, baby-safe objects can keep little hands busy without making play complicated. Taking things out, dropping them back in and choosing what to grab next helps your baby practise control, curiosity and early decision-making. It is simple to repeat and easy to change up.','for_your_child'),
  ('9-12m','9–12 months',9,12,true,'ent_cluster_hands','My hands can do more now',2,true,'ent_need_bilateral','Busy little hands','Your baby may be grabbing, banging, passing toys between hands, raking food or trying tiny finger-and-thumb movements. Everyday play with cups, baskets, chunky pieces and safe household objects can help them practise hand control, focus and early problem-solving in a way that feels like discovery.','for_your_child','cat_two_handed_objects','Two-hand toys and banging games','Two Handed Objects',4,'Passing a toy from one hand to the other, banging two safe objects together or holding something with both hands may look ordinary. It gives your baby useful practice coordinating both sides of the body during playful, noisy moments. It is simple to repeat and easy to change up.','for_your_child'),
  ('9-12m','9–12 months',9,12,true,'ent_cluster_hands','My hands can do more now',2,true,'ent_need_bilateral','Busy little hands','Your baby may be grabbing, banging, passing toys between hands, raking food or trying tiny finger-and-thumb movements. Everyday play with cups, baskets, chunky pieces and safe household objects can help them practise hand control, focus and early problem-solving in a way that feels like discovery.','for_your_child','cat_musical_noise','Clapping, shaking and noisy play','Musical Noise',5,'Clapping, shaking a rattle or banging a safe object can become more than noise. Your baby is noticing rhythm, copying you and learning that their actions can create a response, especially when you smile, pause and join in. It is simple to repeat and easy to change up.','for_your_child'),
  ('9-12m','9–12 months',9,12,true,'ent_cluster_hands','My hands can do more now',2,true,'ent_need_parent_day','Busy little hands','Your baby may be grabbing, banging, passing toys between hands, raking food or trying tiny finger-and-thumb movements. Everyday play with cups, baskets, chunky pieces and safe household objects can help them practise hand control, focus and early problem-solving in a way that feels like discovery.','for_your_child','cat_safe_household_objects','Baby-safe household treasures','Safe Household Objects',6,'A wooden spoon, a clean tub or a soft cloth can be just as interesting as a toy when it is safe and supervised. Everyday objects give your baby new textures, sounds and movements to explore, without adding more clutter.','for_both'),
  ('9-12m','9–12 months',9,12,true,'ent_cluster_solve','I’m finding things out',3,true,'ent_need_container','Finding hidden things','Dropping a ball, lifting a cloth or posting something into a box can suddenly feel fascinating. These repeated little experiments help your baby learn that things can move, hide, come back and make something happen, while building focus and hand control.','for_your_child','cat_peekaboo_scarf','Peekaboo scarves and cloths','Peekaboo Scarf',1,'Hiding your face, a toy or a soft cloth and bringing it back can be endlessly funny at this stage. Peekaboo helps your baby explore disappearing and returning, while also building anticipation, attention and shared laughter. It also gives you an easy moment to join in.','for_your_child'),
  ('9-12m','9–12 months',9,12,true,'ent_cluster_solve','I’m finding things out',3,true,'ent_need_container','Finding hidden things','Dropping a ball, lifting a cloth or posting something into a box can suddenly feel fascinating. These repeated little experiments help your baby learn that things can move, hide, come back and make something happen, while building focus and hand control.','for_your_child','cat_posting_boxes','Posting boxes and hiding lids','Posting Boxes',2,'Posting a chunky piece into a box, sliding a lid or finding something hidden inside gives your baby a clear challenge. It lets them practise hand control and early problem-solving while discovering that objects can go somewhere and come back.','for_your_child'),
  ('9-12m','9–12 months',9,12,true,'ent_cluster_solve','I’m finding things out',3,true,'ent_need_cause','Finding hidden things','Dropping a ball, lifting a cloth or posting something into a box can suddenly feel fascinating. These repeated little experiments help your baby learn that things can move, hide, come back and make something happen, while building focus and hand control.','for_your_child','cat_drop_roll_tubes','Drop, roll and tube games','Drop Roll Tubes',3,'Dropping a ball into a tube or watching it roll across the floor gives your baby a simple experiment to repeat. They can see where things go, try again and begin to connect their action with what happens next. It also gives you an easy moment to join in.','for_your_child'),
  ('9-12m','9–12 months',9,12,true,'ent_cluster_solve','I’m finding things out',3,true,'ent_need_cause','Finding hidden things','Dropping a ball, lifting a cloth or posting something into a box can suddenly feel fascinating. These repeated little experiments help your baby learn that things can move, hide, come back and make something happen, while building focus and hand control.','for_your_child','cat_first_puzzles','Big-piece first puzzles','First Puzzles',4,'Big, easy-to-hold puzzle pieces give your baby something to pick up, turn, test and try again. At this age, the value is not finishing the puzzle neatly, but practising focus, hand control and curiosity. It also gives you an easy moment to join in.','for_your_child'),
  ('9-12m','9–12 months',9,12,true,'ent_cluster_solve','I’m finding things out',3,true,'ent_need_cause','Finding hidden things','Dropping a ball, lifting a cloth or posting something into a box can suddenly feel fascinating. These repeated little experiments help your baby learn that things can move, hide, come back and make something happen, while building focus and hand control.','for_your_child','cat_switchboard','Safe switches, flaps and buttons','Switchboard',5,'Large switches, flaps and buttons can be very satisfying for a baby who wants to make things happen. Simple cause-and-effect play helps them practise hand movements, attention and curiosity, especially when the pieces are safe and sturdy. It also gives you an easy moment to join in.','for_your_child'),
  ('9-12m','9–12 months',9,12,true,'ent_cluster_solve','I’m finding things out',3,true,'ent_need_container','Finding hidden things','Dropping a ball, lifting a cloth or posting something into a box can suddenly feel fascinating. These repeated little experiments help your baby learn that things can move, hide, come back and make something happen, while building focus and hand control.','for_your_child','cat_hide_favourite_toy','Hide-and-find favourite toys','Hide Favourite Toy',6,'If your baby has a favourite toy, hiding it under a cloth or behind a cup can turn a familiar object into a tiny discovery game. Looking, waiting and finding help build memory, attention and shared play. It also gives you an easy moment to join in.','for_both'),
  ('9-12m','9–12 months',9,12,true,'ent_cluster_words','I’m learning to tell you things',4,true,'ent_need_books','Chats, claps and little signs','Your baby may be babbling back, responding to their name, waving, clapping, pointing or copying sounds. Songs, board books, simple signs and naming games help turn these small gestures into shared moments, giving your baby more ways to connect before clear words arrive.','for_your_child','cat_board_books','Board books for pointing and naming','Board Books',1,'A chunky board book gives your baby something to hold, turn, point at and hear named again and again. Looking together helps build shared attention, early language and a calm little routine you can repeat anywhere. It can fit naturally into everyday routines.','for_your_child'),
  ('9-12m','9–12 months',9,12,true,'ent_cluster_words','I’m learning to tell you things',4,true,'ent_need_gestures','Chats, claps and little signs','Your baby may be babbling back, responding to their name, waving, clapping, pointing or copying sounds. Songs, board books, simple signs and naming games help turn these small gestures into shared moments, giving your baby more ways to connect before clear words arrive.','for_your_child','cat_rhyme_games','Rhymes, claps and pat-a-cake','Rhyme Games',2,'Rhymes and clapping games give your baby predictable sounds, pauses and actions to copy. Pat-a-cake, waving songs or simple claps can turn communication into a back-and-forth game, even before clear words arrive. It can fit naturally into everyday routines you already do together.','for_both'),
  ('9-12m','9–12 months',9,12,true,'ent_cluster_words','I’m learning to tell you things',4,true,'ent_need_gestures','Chats, claps and little signs','Your baby may be babbling back, responding to their name, waving, clapping, pointing or copying sounds. Songs, board books, simple signs and naming games help turn these small gestures into shared moments, giving your baby more ways to connect before clear words arrive.','for_your_child','cat_waving_signs','Waving, pointing and simple signs','Waving Signs',3,'A wave, point, arm lift or simple sign can help your baby communicate before words are clear. Repeating these gestures during real routines, like bye-bye, more or all gone, gives them useful ways to join in. It can fit naturally into everyday routines.','for_both'),
  ('9-12m','9–12 months',9,12,true,'ent_cluster_words','I’m learning to tell you things',4,true,'ent_need_gestures','Chats, claps and little signs','Your baby may be babbling back, responding to their name, waving, clapping, pointing or copying sounds. Songs, board books, simple signs and naming games help turn these small gestures into shared moments, giving your baby more ways to connect before clear words arrive.','for_your_child','cat_sound_copy','Copy-me babble games','Sound Copy',4,'When your baby babbles, copying the sound and pausing can make it feel like a conversation. Adding one simple word, smile or gesture helps them learn turn-taking and shows that their sounds are worth listening to. It can fit naturally into everyday routines.','for_both'),
  ('9-12m','9–12 months',9,12,true,'ent_cluster_words','I’m learning to tell you things',4,true,'ent_need_books','Chats, claps and little signs','Your baby may be babbling back, responding to their name, waving, clapping, pointing or copying sounds. Songs, board books, simple signs and naming games help turn these small gestures into shared moments, giving your baby more ways to connect before clear words arrive.','for_your_child','cat_point_name_outings','Point-and-name little outings','Point Name Outings',5,'A walk can become a gentle naming game when your baby looks, points or reaches toward something. Saying simple words like dog, bus or tree helps connect what they notice with language, while giving the day a small reset. It can fit naturally into everyday routines.','for_both'),
  ('9-12m','9–12 months',9,12,true,'ent_cluster_words','I’m learning to tell you things',4,true,'ent_need_books','Chats, claps and little signs','Your baby may be babbling back, responding to their name, waving, clapping, pointing or copying sounds. Songs, board books, simple signs and naming games help turn these small gestures into shared moments, giving your baby more ways to connect before clear words arrive.','for_your_child','cat_family_faces_cards','Family faces and favourite objects','Family Faces Cards',6,'Babies often light up for familiar faces and favourite things. Simple photo cards or object cards give you easy chances to name people, point together and build recognition, especially if your baby is showing clear preferences. It can fit naturally into everyday routines.','for_your_child'),
  ('9-12m','9–12 months',9,12,true,'ent_cluster_feeding','I’m learning to feed myself',5,true,'ent_need_self_feeding','Messy little meals','Mealtimes may start to look busier now, with finger foods, cup practice, lumpy textures and plenty of mess. Safe seating, calm supervision and simple prep help your baby practise eating, drinking and joining family meals without turning every meal into a battle.','for_you','cat_highchair','Safe sitting for messy meals','Highchair',1,'As finger foods and lumpy textures become more common, safe upright seating makes mealtimes easier to manage. A stable highchair or feeding seat helps your baby focus on eating while you can stay close and watch carefully. It keeps the focus on practice, not perfection.','for_you'),
  ('9-12m','9–12 months',9,12,true,'ent_cluster_feeding','I’m learning to feed myself',5,true,'ent_need_self_feeding','Messy little meals','Mealtimes may start to look busier now, with finger foods, cup practice, lumpy textures and plenty of mess. Safe seating, calm supervision and simple prep help your baby practise eating, drinking and joining family meals without turning every meal into a battle.','for_you','cat_open_cup','Tiny open-cup practice','Open Cup',2,'A small open cup with a little water can become a careful practice moment near this stage. Your baby may spill, chew or splash at first, but holding, sipping and trying again can build coordination with your help. It keeps the focus on practice, not perfection.','for_both'),
  ('9-12m','9–12 months',9,12,true,'ent_cluster_feeding','I’m learning to feed myself',5,true,'ent_need_self_feeding','Messy little meals','Mealtimes may start to look busier now, with finger foods, cup practice, lumpy textures and plenty of mess. Safe seating, calm supervision and simple prep help your baby practise eating, drinking and joining family meals without turning every meal into a battle.','for_you','cat_finger_food_prep','Finger foods cut safely','Finger Food Prep',3,'Finger foods give your baby a hands-on way to explore texture, grip and chewing. The adult job is to make the food safe: soft enough, cut to the right shape and watched closely while your baby experiments. It keeps the focus on practice, not perfection.','for_you'),
  ('9-12m','9–12 months',9,12,true,'ent_cluster_feeding','I’m learning to feed myself',5,true,'ent_need_mealtime','Messy little meals','Mealtimes may start to look busier now, with finger foods, cup practice, lumpy textures and plenty of mess. Safe seating, calm supervision and simple prep help your baby practise eating, drinking and joining family meals without turning every meal into a battle.','for_you','cat_bibs_mats','Bibs, mats and clean-up helpers','Bibs Mats',4,'Self-feeding often means food on hands, clothes, hair and floor. Bibs, splash mats and simple clean-up helpers can make that mess easier to tolerate, so your baby still gets the practice of touching, gripping and tasting. It keeps the focus on practice, not perfection.','for_you'),
  ('9-12m','9–12 months',9,12,true,'ent_cluster_feeding','I’m learning to feed myself',5,true,'ent_need_mealtime','Messy little meals','Mealtimes may start to look busier now, with finger foods, cup practice, lumpy textures and plenty of mess. Safe seating, calm supervision and simple prep help your baby practise eating, drinking and joining family meals without turning every meal into a battle.','for_you','cat_family_meal_plan','Joining simple family meals','Family Meal Plan',5,'By the end of the first year, your baby may be joining more regular meals alongside milk. Simple family food, adapted safely, lets them watch, copy and practise eating with you, while keeping salt, sugar and choking risks in mind.','for_you'),
  ('9-12m','9–12 months',9,12,true,'ent_cluster_feeding','I’m learning to feed myself',5,true,'ent_need_mealtime','Messy little meals','Mealtimes may start to look busier now, with finger foods, cup practice, lumpy textures and plenty of mess. Safe seating, calm supervision and simple prep help your baby practise eating, drinking and joining family meals without turning every meal into a battle.','for_you','cat_pouches_caution','Using pouches without relying on them','Pouches Caution',6,'Pouches can be helpful on difficult days, but they are not the same as exploring real textures and finger foods. Using them occasionally, and serving from a spoon, keeps convenience in its place while your baby keeps practising. It keeps the focus on practice, not perfection.','for_you'),
  ('9-12m','9–12 months',9,12,true,'ent_cluster_safety','I’m suddenly into everything',6,true,'ent_need_babyproof','Babyproofing the new mover','Once your baby crawls, pulls up or mouths everything, the home can change overnight. This is a good time to check stairs, furniture, cupboards, cords and water routines, so your baby has room to explore while the big risks are calmly managed.','for_you','cat_stair_gates','Stair gates before the big climb','Stair Gates',1,'Once your baby starts moving, stairs can become interesting very quickly. Fitting stair gates where needed helps protect those sudden crawling, climbing or cruising attempts, while still giving your baby safer places to explore nearby. It gives your baby more freedom within safer limits.','for_you'),
  ('9-12m','9–12 months',9,12,true,'ent_cluster_safety','I’m suddenly into everything',6,true,'ent_need_babyproof','Babyproofing the new mover','Once your baby crawls, pulls up or mouths everything, the home can change overnight. This is a good time to check stairs, furniture, cupboards, cords and water routines, so your baby has room to explore while the big risks are calmly managed.','for_you','cat_furniture_anchors','Anchored furniture for pull-up practice','Furniture Anchors',2,'Pulling up often happens on whatever is closest: a chair, shelf, drawer or low table. Anchoring furniture and checking unstable pieces helps make the room safer for those wobbly standing attempts and curious hands. It gives your baby more freedom within safer limits.','for_you'),
  ('9-12m','9–12 months',9,12,true,'ent_cluster_safety','I’m suddenly into everything',6,true,'ent_need_babyproof','Babyproofing the new mover','Once your baby crawls, pulls up or mouths everything, the home can change overnight. This is a good time to check stairs, furniture, cupboards, cords and water routines, so your baby has room to explore while the big risks are calmly managed.','for_you','cat_cupboard_locks','Cupboard locks for curious hands','Cupboard Locks',3,'Opening cupboards can become a new favourite experiment once your baby is mobile. Locks and safer storage help keep cleaning products, medicines and small hazards out of reach, so curiosity can continue in safer places. It gives your baby more freedom within safer limits.','for_you'),
  ('9-12m','9–12 months',9,12,true,'ent_cluster_safety','I’m suddenly into everything',6,true,'ent_need_babyproof','Babyproofing the new mover','Once your baby crawls, pulls up or mouths everything, the home can change overnight. This is a good time to check stairs, furniture, cupboards, cords and water routines, so your baby has room to explore while the big risks are calmly managed.','for_you','cat_blind_cord_cleats','Blind-cord tidies and cleats','Blind Cord Cleats',4,'A dangling blind cord can look like something to pull or chew. Tidying cords with cleats or cordless options removes a serious risk from the room, especially as your baby starts reaching higher and moving more confidently. It gives your baby more freedom within safer limits.','for_you'),
  ('9-12m','9–12 months',9,12,true,'ent_cluster_safety','I’m suddenly into everything',6,true,'ent_need_bath','Babyproofing the new mover','Once your baby crawls, pulls up or mouths everything, the home can change overnight. This is a good time to check stairs, furniture, cupboards, cords and water routines, so your baby has room to explore while the big risks are calmly managed.','for_you','cat_bath_supervision','Safe bath and water-play routines','Bath Supervision',5,'Bath cups, splashing and pouring can be lovely at this age, but water needs close attention every time. A simple routine, everything within reach and constant supervision help make water play enjoyable without taking safety for granted. It gives your baby more freedom within safer limits.','for_you'),
  ('9-12m','9–12 months',9,12,true,'ent_cluster_safety','I’m suddenly into everything',6,true,'ent_need_babyproof','Babyproofing the new mover','Once your baby crawls, pulls up or mouths everything, the home can change overnight. This is a good time to check stairs, furniture, cupboards, cords and water routines, so your baby has room to explore while the big risks are calmly managed.','for_you','cat_exclude_baby_walker','Skip seated baby walkers','Exclude Baby Walker',6,'Seated baby walkers can look like a quick way to help movement, but they bring safety risks and do not help babies learn to walk well. Safer floor play, crawling space and steady surfaces are better routes for practice. It gives your baby more freedom within safer limits.','for_you'),
  ('9-12m','9–12 months',9,12,true,'ent_cluster_stories','I’m noticing faces and feelings',7,true,'ent_need_emotion','Faces, feelings and little stories','Your baby may show favourite people, familiar toys and early reactions to faces or voices. Simple books, photo cards, puppets and soft toys can make naming, comfort and early feelings easier to share, while giving you lovely repeatable moments together.','for_your_child','cat_feelings_faces_books','Baby faces and feelings books','Feelings Faces Books',1,'Books with baby faces, simple expressions or familiar routines give you easy moments to point, name and react together. Your baby may not understand feelings fully yet, but they can enjoy faces, voices and shared attention. It is gentle, repeatable and easy to share.','for_your_child'),
  ('9-12m','9–12 months',9,12,true,'ent_cluster_stories','I’m noticing faces and feelings',7,true,'ent_need_emotion','Faces, feelings and little stories','Your baby may show favourite people, familiar toys and early reactions to faces or voices. Simple books, photo cards, puppets and soft toys can make naming, comfort and early feelings easier to share, while giving you lovely repeatable moments together.','for_your_child','cat_soft_doll','Soft doll or cuddly care play','Soft Doll',2,'A soft doll or cuddly toy can become part of simple care play: patting, cuddling, handing over or finding again. These small moments support comfort, imitation and connection without needing complicated pretend play. It is gentle, repeatable and easy to share.','for_your_child'),
  ('9-12m','9–12 months',9,12,true,'ent_cluster_stories','I’m noticing faces and feelings',7,true,'ent_need_books','Faces, feelings and little stories','Your baby may show favourite people, familiar toys and early reactions to faces or voices. Simple books, photo cards, puppets and soft toys can make naming, comfort and early feelings easier to share, while giving you lovely repeatable moments together.','for_your_child','cat_animal_mini_books','Little animal books','Animal Mini Books',3,'Small animal books are easy to hold, chew, point at and revisit. Naming the animal, making the sound and waiting for your baby’s reaction turns a simple book into shared attention, sound play and early vocabulary. It is gentle, repeatable and easy to share.','for_your_child'),
  ('9-12m','9–12 months',9,12,true,'ent_cluster_stories','I’m noticing faces and feelings',7,true,'ent_need_emotion','Faces, feelings and little stories','Your baby may show favourite people, familiar toys and early reactions to faces or voices. Simple books, photo cards, puppets and soft toys can make naming, comfort and early feelings easier to share, while giving you lovely repeatable moments together.','for_your_child','cat_puppets','Puppets and silly voices','Puppets',4,'A puppet or funny voice can make a familiar song or book feel new again. Your baby may watch, smile, reach or babble back, giving you an easy way to stretch a small moment into shared play. It is gentle, repeatable and easy to share.','for_both'),
  ('9-12m','9–12 months',9,12,true,'ent_cluster_stories','I’m noticing faces and feelings',7,true,'ent_need_emotion','Faces, feelings and little stories','Your baby may show favourite people, familiar toys and early reactions to faces or voices. Simple books, photo cards, puppets and soft toys can make naming, comfort and early feelings easier to share, while giving you lovely repeatable moments together.','for_your_child','cat_family_photos','Family photos and familiar faces','Family Photos',5,'Photos of familiar people can be surprisingly powerful when your baby is tuned into favourite adults. Pointing, naming and smiling at the pictures helps connect faces with words and can make separation or waiting moments feel calmer. It is gentle, repeatable and easy to share.','for_your_child'),
  ('9-12m','9–12 months',9,12,true,'ent_cluster_stories','I’m noticing faces and feelings',7,true,'ent_need_bilateral','Faces, feelings and little stories','Your baby may show favourite people, familiar toys and early reactions to faces or voices. Simple books, photo cards, puppets and soft toys can make naming, comfort and early feelings easier to share, while giving you lovely repeatable moments together.','for_your_child','cat_texture_sensory','Texture balls for touching and rolling','Texture Sensory',6,'A textured ball gives your baby something to squeeze, roll, mouth, pass and chase. Different surfaces can make the object more interesting, while the simple rolling game still builds reaching, grip and shared attention. It is gentle, repeatable and easy to share.','for_your_child'),
  ('9-12m','9–12 months',9,12,true,'ent_cluster_days','Give me a good little moment',8,true,'ent_need_parent_day','Simple ways to fill the day','Some days just need an easy reset: a pram walk, a library mat, bubbles, bath cups or a basket of safe objects. These small moments give your baby something fresh to reach, watch, name or explore, without making you feel you need to buy more.','for_both','cat_pram_walks','Pram walks with naming','Pram Walks',1,'A pram walk can be a good reset for both of you. Naming what you pass, pausing for sounds and following your baby’s gaze turns an ordinary outing into gentle language, attention and connection practice. It keeps the day moving without adding pressure.','for_both'),
  ('9-12m','9–12 months',9,12,true,'ent_cluster_days','Give me a good little moment',8,true,'ent_need_parent_day','Simple ways to fill the day','Some days just need an easy reset: a pram walk, a library mat, bubbles, bath cups or a basket of safe objects. These small moments give your baby something fresh to reach, watch, name or explore, without making you feel you need to buy more.','for_both','cat_library_baby_group','Library or baby-group floor time','Library Baby Group',2,'A library mat or baby group gives your baby new faces, sounds and objects to notice, while you get a change of scene. The value is not a packed schedule, just a fresh little social and movement moment. It keeps the day moving without adding pressure.','for_you'),
  ('9-12m','9–12 months',9,12,true,'ent_cluster_days','Give me a good little moment',8,true,'ent_need_parent_day','Simple ways to fill the day','Some days just need an easy reset: a pram walk, a library mat, bubbles, bath cups or a basket of safe objects. These small moments give your baby something fresh to reach, watch, name or explore, without making you feel you need to buy more.','for_both','cat_bubbles','Bubbles to watch and reach for','Bubbles',3,'Bubbles are simple but captivating: they float, pop, disappear and come back again. Watching, reaching and laughing together can support attention, tracking and shared joy, especially when you need a quick activity at home. It keeps the day moving without adding pressure.','for_both'),
  ('9-12m','9–12 months',9,12,true,'ent_cluster_days','Give me a good little moment',8,true,'ent_need_parent_day','Simple ways to fill the day','Some days just need an easy reset: a pram walk, a library mat, bubbles, bath cups or a basket of safe objects. These small moments give your baby something fresh to reach, watch, name or explore, without making you feel you need to buy more.','for_both','cat_bath_cups','Bath cups and pouring','Bath Cups',4,'Pouring water between cups in the bath gives your baby a safe, contained way to explore movement and control. Scooping, tipping and watching water fall can be fascinating, as long as an adult stays close throughout. It keeps the day moving without adding pressure.','for_both'),
  ('9-12m','9–12 months',9,12,true,'ent_cluster_days','Give me a good little moment',8,true,'ent_need_parent_day','Simple ways to fill the day','Some days just need an easy reset: a pram walk, a library mat, bubbles, bath cups or a basket of safe objects. These small moments give your baby something fresh to reach, watch, name or explore, without making you feel you need to buy more.','for_both','cat_toy_rotation','Tiny toy rotation basket','Toy Rotation',5,'Putting a few safe objects in a small basket and swapping them around can make play feel new without buying more. Your baby gets a fresh choice, and you get a simple way to reduce clutter and decision fatigue. It keeps the day moving without adding pressure.','for_you'),
  ('9-12m','9–12 months',9,12,true,'ent_cluster_days','Give me a good little moment',8,true,'ent_need_parent_day','Simple ways to fill the day','Some days just need an easy reset: a pram walk, a library mat, bubbles, bath cups or a basket of safe objects. These small moments give your baby something fresh to reach, watch, name or explore, without making you feel you need to buy more.','for_both','cat_safe_laundry_play','Supervised laundry basket play','Safe Laundry Play',6,'A laundry basket can become a simple supervised game: taking cloths out, putting them back, peeking through holes or crawling around it. It gives your baby texture, hiding and movement practice using something already in the house. It keeps the day moving without adding pressure.','for_both'),
  ('13-15m','13–15 months',13,15,true,'ent_cluster_move','I’m off and moving',1,true,'ent_need_13_15_safe_movement','First steps and safe movement','Your toddler may be cruising, taking wobbly steps or trying to climb anything nearby. This cluster turns that burst of movement into safer practice, with steady surfaces, simple movement games and home checks that make exploring feel exciting without leaving you constantly on edge.','for_both','cat_safe_floor_space','A clear floor space','Safe Floor Space',1,'Your toddler may suddenly cross the room, crawl faster or pull up where you did not expect it. A clear patch of floor gives them space to move, fall softly, recover and try again, while you reduce obvious trip hazards and sharp edges nearby.','for_both'),
  ('13-15m','13–15 months',13,15,true,'ent_cluster_move','I’m off and moving',1,true,'ent_need_13_15_safe_movement','First steps and safe movement','Your toddler may be cruising, taking wobbly steps or trying to climb anything nearby. This cluster turns that burst of movement into safer practice, with steady surfaces, simple movement games and home checks that make exploring feel exciting without leaving you constantly on edge.','for_both','cat_cruising_furniture','Steady cruising surfaces','Cruising Furniture',2,'Low, stable surfaces give a new mover something to lean on, cruise along and practise balance. The aim is not to force walking, but to make everyday standing safer and easier to supervise, especially as they start using furniture to explore.','for_both'),
  ('13-15m','13–15 months',13,15,true,'ent_cluster_move','I’m off and moving',1,true,'ent_need_13_15_safe_movement','First steps and safe movement','Your toddler may be cruising, taking wobbly steps or trying to climb anything nearby. This cluster turns that burst of movement into safer practice, with steady surfaces, simple movement games and home checks that make exploring feel exciting without leaving you constantly on edge.','for_both','cat_push_pull_toys','Sturdy push-and-pull toys','Push Pull Toys',3,'A stable push toy or pull-along can give your toddler a reason to move, stop, turn and try again. It is best treated as playful practice for children already showing readiness, not as a shortcut to walking or a seated walker substitute.','for_both'),
  ('13-15m','13–15 months',13,15,true,'ent_cluster_move','I’m off and moving',1,true,'ent_need_13_15_safe_movement','First steps and safe movement','Your toddler may be cruising, taking wobbly steps or trying to climb anything nearby. This cluster turns that burst of movement into safer practice, with steady surfaces, simple movement games and home checks that make exploring feel exciting without leaving you constantly on edge.','for_both','cat_soft_graspable_balls','Soft balls to roll and chase','Soft Graspable Balls',4,'A soft ball gives your toddler a clear reason to move: roll it away, crawl after it, bring it back or copy your throw. The game can stretch balance, coordination and shared attention while staying simple, cheap and easy to repeat indoors or outside.','for_both'),
  ('13-15m','13–15 months',13,15,true,'ent_cluster_move','I’m off and moving',1,true,'ent_need_13_15_safe_movement','First steps and safe movement','Your toddler may be cruising, taking wobbly steps or trying to climb anything nearby. This cluster turns that burst of movement into safer practice, with steady surfaces, simple movement games and home checks that make exploring feel exciting without leaving you constantly on edge.','for_both','cat_park_swing_walks','Park walks and toddler swings','Park Swing Walks',5,'A short walk or closely supervised swing can reset both of you. Your toddler gets movement, changing sights and things to point at, while you get easy naming moments: dog, bus, tree, swing. It is useful because it combines movement, language and a change of scene.','for_both'),
  ('13-15m','13–15 months',13,15,true,'ent_cluster_hands','I’m posting, stacking and finding out',2,true,'ent_need_13_15_hands_experiments','Posting, stacking and little experiments','At this stage, dropping, posting, stacking and taking things apart can become wonderfully absorbing. Your toddler is not making a mess for no reason. They are testing how objects move, fit, disappear and come back, while building hand control, focus and early problem-solving.','for_your_child','cat_stacking_nesting_cups','Stacking and nesting cups','Stacking Nesting Cups',1,'Cups can be stacked, nested, filled, tipped, posted into, hidden under and used in the bath. That flexibility makes them especially strong at this stage, when toddlers enjoy repeating the same little experiment and watching what changes each time.','for_your_child'),
  ('13-15m','13–15 months',13,15,true,'ent_cluster_hands','I’m posting, stacking and finding out',2,true,'ent_need_13_15_hands_experiments','Posting, stacking and little experiments','At this stage, dropping, posting, stacking and taking things apart can become wonderfully absorbing. Your toddler is not making a mess for no reason. They are testing how objects move, fit, disappear and come back, while building hand control, focus and early problem-solving.','for_your_child','cat_posting_coin_box','Posting boxes and coin slots','Posting Coin Box',2,'Posting a chunky coin or shape into a slot gives your toddler a clear challenge: hold, aim, release, then try again. It builds finger control and persistence, and the satisfying drop can make the practice feel like play rather than a task.','for_your_child'),
  ('13-15m','13–15 months',13,15,true,'ent_cluster_hands','I’m posting, stacking and finding out',2,true,'ent_need_13_15_hands_experiments','Posting, stacking and little experiments','At this stage, dropping, posting, stacking and taking things apart can become wonderfully absorbing. Your toddler is not making a mess for no reason. They are testing how objects move, fit, disappear and come back, while building hand control, focus and early problem-solving.','for_your_child','cat_object_permanence_box','Hide-and-find boxes','Object Permanence Box',3,'When a ball or toy vanishes into a box and comes back, your toddler gets a tiny mystery to solve. These hide-and-find moments support attention, memory and cause-and-effect, especially when you keep the game slow enough for them to watch and join in.','for_your_child'),
  ('13-15m','13–15 months',13,15,true,'ent_cluster_hands','I’m posting, stacking and finding out',2,true,'ent_need_13_15_hands_experiments','Posting, stacking and little experiments','At this stage, dropping, posting, stacking and taking things apart can become wonderfully absorbing. Your toddler is not making a mess for no reason. They are testing how objects move, fit, disappear and come back, while building hand control, focus and early problem-solving.','for_your_child','cat_shape_peg_puzzles','Chunky shape and peg puzzles','Shape Peg Puzzles',4,'A chunky puzzle does not need to be completed perfectly to be valuable. Picking up a piece, turning it, testing where it fits and trying again gives your toddler useful practice with focus, hand control and early spatial thinking.','for_your_child'),
  ('13-15m','13–15 months',13,15,true,'ent_cluster_hands','I’m posting, stacking and finding out',2,true,'ent_need_13_15_hands_experiments','Posting, stacking and little experiments','At this stage, dropping, posting, stacking and taking things apart can become wonderfully absorbing. Your toddler is not making a mess for no reason. They are testing how objects move, fit, disappear and come back, while building hand control, focus and early problem-solving.','for_your_child','cat_tower_blocks','First tower blocks','Tower Blocks',5,'Stacking two blocks, knocking them down and starting again is a neat little experiment. Your toddler practises hand control, cause-and-effect and anticipation, while also learning that repeating the same action can produce a predictable result.','for_your_child'),
  ('13-15m','13–15 months',13,15,true,'ent_cluster_words','I’m telling you things',3,true,'ent_need_13_15_words_pointing','Pointing, words and little chats','Your toddler may point, look back at you, try a new word or bring you something familiar. These small exchanges are the start of real communication. Books, songs, gestures and naming games give you easy ways to respond and stretch the moment without making it feel like a lesson.','for_your_child','cat_board_books','Board books and face books','Board Books',1,'A sturdy board book gives your toddler something to hold, turn, point at and hear named again and again. If they grab the book or chew the corner, the moment can still count: short, repeatable pages are often more realistic than a perfect storytime.','for_your_child'),
  ('13-15m','13–15 months',13,15,true,'ent_cluster_words','I’m telling you things',3,true,'ent_need_13_15_words_pointing','Pointing, words and little chats','Your toddler may point, look back at you, try a new word or bring you something familiar. These small exchanges are the start of real communication. Books, songs, gestures and naming games give you easy ways to respond and stretch the moment without making it feel like a lesson.','for_your_child','cat_picture_word_cards','Picture and word cards','Picture Word Cards',2,'Simple picture cards, family photos or object cards can make naming feel concrete. Your toddler can point, look back at you, hand one over or wait for the word, giving you an easy way to turn everyday vocabulary into a shared moment.','for_your_child'),
  ('13-15m','13–15 months',13,15,true,'ent_cluster_words','I’m telling you things',3,true,'ent_need_13_15_words_pointing','Pointing, words and little chats','Your toddler may point, look back at you, try a new word or bring you something familiar. These small exchanges are the start of real communication. Books, songs, gestures and naming games give you easy ways to respond and stretch the moment without making it feel like a lesson.','for_your_child','cat_songs_action_games','Songs and action games','Songs Action Games',3,'Action songs give your toddler a predictable pattern: listen, watch, clap, wave, pause and try a sound. Wheels on the Bus, pat-a-cake or a clean-up song can turn communication into a back-and-forth game without needing any new kit.','for_your_child'),
  ('13-15m','13–15 months',13,15,true,'ent_cluster_words','I’m telling you things',3,true,'ent_need_13_15_words_pointing','Pointing, words and little chats','Your toddler may point, look back at you, try a new word or bring you something familiar. These small exchanges are the start of real communication. Books, songs, gestures and naming games give you easy ways to respond and stretch the moment without making it feel like a lesson.','for_your_child','cat_gesture_sign_games','First gestures and simple signs','Gesture Sign Games',4,'Pointing, waving, arms up, more and all gone can reduce guesswork when words are still emerging. Repeating gestures during real routines helps your toddler see that their signals make something happen, which can build confidence and connection.','for_your_child'),
  ('13-15m','13–15 months',13,15,true,'ent_cluster_words','I’m telling you things',3,true,'ent_need_13_15_words_pointing','Pointing, words and little chats','Your toddler may point, look back at you, try a new word or bring you something familiar. These small exchanges are the start of real communication. Books, songs, gestures and naming games give you easy ways to respond and stretch the moment without making it feel like a lesson.','for_your_child','cat_pretend_phone_talk','Pretend phone and object talk','Pretend Phone Talk',5,'A toy phone, cup, brush or spoon can become a little language prompt when your toddler copies what you do. Naming the object, acting it out and waiting for their sound or gesture builds understanding, imitation and a playful reason to communicate.','for_your_child'),
  ('13-15m','13–15 months',13,15,true,'ent_cluster_copying_everyday','I’m copying the everyday',4,true,'ent_need_13_15_copying_everyday','Copying everyday life','Phones, cups, shoes, brushes and soft toys can suddenly become fascinating because your toddler is watching what people do. Copying these little routines helps them connect objects with meaning, practise social understanding and join family life through simple, repeatable pretend moments.','for_your_child','cat_safe_household_objects','Safe everyday-object play','Safe Household Objects',1,'A clean tub, wooden spoon, shoe, soft cloth or empty box can be just as interesting as a toy when it is safe and supervised. Everyday objects help your toddler practise choosing, copying, carrying and using things with purpose, while keeping play grounded in real life.','for_your_child'),
  ('13-15m','13–15 months',13,15,true,'ent_cluster_copying_everyday','I’m copying the everyday',4,true,'ent_need_13_15_copying_everyday','Copying everyday life','Phones, cups, shoes, brushes and soft toys can suddenly become fascinating because your toddler is watching what people do. Copying these little routines helps them connect objects with meaning, practise social understanding and join family life through simple, repeatable pretend moments.','for_your_child','cat_doll_soft_toy_care','Dolls and soft-toy care','Doll Soft Toy Care',2,'A soft toy or doll can become part of simple care play: hugging, patting, feeding, putting to bed or handing over. These are small social moments, but they help your toddler copy familiar routines and practise early affection and empathy.','for_your_child'),
  ('13-15m','13–15 months',13,15,true,'ent_cluster_copying_everyday','I’m copying the everyday',4,true,'ent_need_13_15_copying_everyday','Copying everyday life','Phones, cups, shoes, brushes and soft toys can suddenly become fascinating because your toddler is watching what people do. Copying these little routines helps them connect objects with meaning, practise social understanding and join family life through simple, repeatable pretend moments.','for_your_child','cat_toy_cups_spoons','Toy cups, spoons and plates','Toy Cups Spoons',3,'Pretending to drink from a cup or feed a soft toy is simple, but it links real routines with play. Your toddler can copy you, practise object use and turn familiar mealtime objects into early pretend moments, without needing a full play kitchen.','for_your_child'),
  ('13-15m','13–15 months',13,15,true,'ent_cluster_copying_everyday','I’m copying the everyday',4,true,'ent_need_13_15_copying_everyday','Copying everyday life','Phones, cups, shoes, brushes and soft toys can suddenly become fascinating because your toddler is watching what people do. Copying these little routines helps them connect objects with meaning, practise social understanding and join family life through simple, repeatable pretend moments.','for_your_child','cat_cleanup_basket','Clean-up basket games','Cleanup Basket',4,'Putting socks in a basket or toys into a box can become a little game. It gives your toddler a useful job, a clear target and a satisfying finish, while also turning cleanup into language, cooperation and movement practice.','for_your_child'),
  ('13-15m','13–15 months',13,15,true,'ent_cluster_copying_everyday','I’m copying the everyday',4,true,'ent_need_13_15_copying_everyday','Copying everyday life','Phones, cups, shoes, brushes and soft toys can suddenly become fascinating because your toddler is watching what people do. Copying these little routines helps them connect objects with meaning, practise social understanding and join family life through simple, repeatable pretend moments.','for_your_child','cat_pretend_shoes_brushes','Shoes, brushes and getting-ready play','Pretend Shoes Brushes',5,'Shoes, hats and brushes are everyday objects with obvious meaning. Your toddler may fetch a shoe, hold out a foot or copy brushing, turning the getting-ready rush into a short naming and imitation opportunity when you have the patience for it.','for_your_child'),
  ('13-15m','13–15 months',13,15,true,'ent_cluster_feeding','I’m feeding myself',5,true,'ent_job_13_15_self_feeding','Messy meals and self-feeding','Mealtimes may now involve finger foods, cup spills, spoon attempts and a strong wish to do it themselves. This cluster helps parents set up safe, manageable practice: steady seating, simple cups, easy-clean gear and food choices that support independence without turning every meal into a battle.','for_both','cat_highchair','A supportive highchair','Highchair',1,'At 13-15 months, meals can be busy, messy and hands-on. A stable highchair or feeding seat keeps your toddler upright while they practise finger foods, cup use and spoon attempts, giving you a safer, calmer place to supervise and clean up.','for_both'),
  ('13-15m','13–15 months',13,15,true,'ent_cluster_feeding','I’m feeding myself',5,true,'ent_job_13_15_self_feeding','Messy meals and self-feeding','Mealtimes may now involve finger foods, cup spills, spoon attempts and a strong wish to do it themselves. This cluster helps parents set up safe, manageable practice: steady seating, simple cups, easy-clean gear and food choices that support independence without turning every meal into a battle.','for_both','cat_open_cup','An open or free-flow cup','Open Cup',2,'A small cup with a little water or milk gives your toddler a real skill to practise. There will be spills, chewing and tipping, but holding, lifting and trying again helps coordination and independence during normal meals.','for_both'),
  ('13-15m','13–15 months',13,15,true,'ent_cluster_feeding','I’m feeding myself',5,true,'ent_job_13_15_self_feeding','Messy meals and self-feeding','Mealtimes may now involve finger foods, cup spills, spoon attempts and a strong wish to do it themselves. This cluster helps parents set up safe, manageable practice: steady seating, simple cups, easy-clean gear and food choices that support independence without turning every meal into a battle.','for_both','cat_first_spoons_bowls','Toddler spoons and bowls','First Spoons Bowls',3,'Trying a spoon can be slow, messy and very imperfect, but it gives your toddler a way to join in. Small spoons, stable bowls and relaxed expectations make self-feeding easier to practise without turning every mouthful into a power struggle.','for_both'),
  ('13-15m','13–15 months',13,15,true,'ent_cluster_feeding','I’m feeding myself',5,true,'ent_job_13_15_self_feeding','Messy meals and self-feeding','Mealtimes may now involve finger foods, cup spills, spoon attempts and a strong wish to do it themselves. This cluster helps parents set up safe, manageable practice: steady seating, simple cups, easy-clean gear and food choices that support independence without turning every meal into a battle.','for_both','cat_weaning_bibs_mat','Bibs and splash mats','Weaning Bibs Mat',4,'A bib or floor mat will not teach eating, but it can make practice feel less stressful. When cleanup is easier, parents are more likely to let toddlers touch, grip, spill, scoop and try again, which is exactly how self-feeding improves.','for_both'),
  ('13-15m','13–15 months',13,15,true,'ent_cluster_feeding','I’m feeding myself',5,true,'ent_job_13_15_self_feeding','Messy meals and self-feeding','Mealtimes may now involve finger foods, cup spills, spoon attempts and a strong wish to do it themselves. This cluster helps parents set up safe, manageable practice: steady seating, simple cups, easy-clean gear and food choices that support independence without turning every meal into a battle.','for_both','cat_snack_prep_pots','Snack pots and safe food prep','Snack Prep Pots',5,'Toddlers may need two healthy snacks as well as meals. Small snack pots, simple prep and safe shapes can help days out, nursery handovers and hungry moments feel easier, while still keeping salt, sugar and choking risks in view.','for_both'),
  ('13-15m','13–15 months',13,15,true,'ent_cluster_routines_feelings','Help me settle and reconnect',6,true,'ent_job_13_15_routines_feelings','Bedtime, teeth and big feelings','A one-year-old can be affectionate, frustrated, clingy and determined, sometimes all in the same hour. Familiar routines, bedtime books, comfort objects, toothbrushing and simple feeling words give parents steady anchors, helping daily care feel more predictable while your toddler practises connection and control.','for_both','cat_bedtime_board_books','Bedtime board books','Bedtime Board Books',1,'A short bedtime book can give your toddler a repeated cue: pyjamas, teeth, book, cuddle, sleep. The story matters less than the rhythm. Familiar pages help language, comfort and routine without needing a long, perfect read every night.','for_both'),
  ('13-15m','13–15 months',13,15,true,'ent_cluster_routines_feelings','Help me settle and reconnect',6,true,'ent_job_13_15_routines_feelings','Bedtime, teeth and big feelings','A one-year-old can be affectionate, frustrated, clingy and determined, sometimes all in the same hour. Familiar routines, bedtime books, comfort objects, toothbrushing and simple feeling words give parents steady anchors, helping daily care feel more predictable while your toddler practises connection and control.','for_both','cat_toothbrush_toothpaste','Toddler toothbrush and toothpaste','Toothbrush Toothpaste',2,'A small toothbrush and age-appropriate fluoride toothpaste support a routine that starts before toddlers can do it themselves. The parent still brushes, but songs, mirrors or a familiar order can make the twice-daily habit less of a battle.','for_both'),
  ('13-15m','13–15 months',13,15,true,'ent_cluster_routines_feelings','Help me settle and reconnect',6,true,'ent_job_13_15_routines_feelings','Bedtime, teeth and big feelings','A one-year-old can be affectionate, frustrated, clingy and determined, sometimes all in the same hour. Familiar routines, bedtime books, comfort objects, toothbrushing and simple feeling words give parents steady anchors, helping daily care feel more predictable while your toddler practises connection and control.','for_both','cat_comfort_toy','A safe comfort object','Comfort Toy',3,'A favourite soft toy or comforter can help some toddlers reconnect during separation, travel or bedtime. It can also become part of simple care play, giving your child a familiar thing to hug, find and include in routines.','for_both'),
  ('13-15m','13–15 months',13,15,true,'ent_cluster_routines_feelings','Help me settle and reconnect',6,true,'ent_job_13_15_routines_feelings','Bedtime, teeth and big feelings','A one-year-old can be affectionate, frustrated, clingy and determined, sometimes all in the same hour. Familiar routines, bedtime books, comfort objects, toothbrushing and simple feeling words give parents steady anchors, helping daily care feel more predictable while your toddler practises connection and control.','for_both','cat_feelings_faces_books','Baby faces and feelings books','Feelings Faces Books',4,'A faces or feelings book gives you a gentle way to name happy, sad, cross or tired when the moment is calm. Your toddler will not manage feelings neatly yet, but repeated words and expressions can help them begin to connect faces, sounds and comfort.','for_both'),
  ('13-15m','13–15 months',13,15,true,'ent_cluster_routines_feelings','Help me settle and reconnect',6,true,'ent_job_13_15_routines_feelings','Bedtime, teeth and big feelings','A one-year-old can be affectionate, frustrated, clingy and determined, sometimes all in the same hour. Familiar routines, bedtime books, comfort objects, toothbrushing and simple feeling words give parents steady anchors, helping daily care feel more predictable while your toddler practises connection and control.','for_both','cat_routine_songs','Routine songs and transition cues','Routine Songs',5,'A clean-up song, toothbrushing song or goodbye wave can soften the small transitions that often trigger frustration. The repetition helps your toddler know what comes next, while giving you a low-effort way to guide behaviour without lengthy explanations.','for_both'),
  ('13-15m','13–15 months',13,15,true,'ent_cluster_safety','I’m suddenly into everything',7,true,'ent_job_13_15_home_safety','Home safety for curious climbers','More movement means more reach, more opening, more climbing and more surprises. This cluster is for the parent job around the child’s development: gates, locks, cords, batteries, furniture and toy checks. It helps your toddler explore a bigger world while the riskiest hazards stay out of reach.','for_you','cat_safety_gates','Safety gates','Safety Gates',1,'Stairs can become fascinating as soon as crawling, cruising or climbing feels possible. Safety gates help keep the biggest risk areas contained, giving your toddler safer places to practise movement while you stay close and supervise.','for_you'),
  ('13-15m','13–15 months',13,15,true,'ent_cluster_safety','I’m suddenly into everything',7,true,'ent_job_13_15_home_safety','Home safety for curious climbers','More movement means more reach, more opening, more climbing and more surprises. This cluster is for the parent job around the child’s development: gates, locks, cords, batteries, furniture and toy checks. It helps your toddler explore a bigger world while the riskiest hazards stay out of reach.','for_you','cat_cupboard_locks','Cupboard locks','Cupboard Locks',2,'Opening cupboards can become a favourite experiment. Locks and safer storage keep medicines, chemicals and cleaning products out of reach, so your toddler can keep exploring lower-risk objects while the dangerous things stay unavailable.','for_you'),
  ('13-15m','13–15 months',13,15,true,'ent_cluster_safety','I’m suddenly into everything',7,true,'ent_job_13_15_home_safety','Home safety for curious climbers','More movement means more reach, more opening, more climbing and more surprises. This cluster is for the parent job around the child’s development: gates, locks, cords, batteries, furniture and toy checks. It helps your toddler explore a bigger world while the riskiest hazards stay out of reach.','for_you','cat_furniture_anchors','Furniture anchors and corner checks','Furniture Anchors',3,'Pulling up often happens on whatever is closest: shelves, drawers, side tables or the sofa. Anchoring unstable furniture and checking hard corners helps prepare the room for a child who is stronger, taller and far less predictable than last month.','for_you'),
  ('13-15m','13–15 months',13,15,true,'ent_cluster_safety','I’m suddenly into everything',7,true,'ent_job_13_15_home_safety','Home safety for curious climbers','More movement means more reach, more opening, more climbing and more surprises. This cluster is for the parent job around the child’s development: gates, locks, cords, batteries, furniture and toy checks. It helps your toddler explore a bigger world while the riskiest hazards stay out of reach.','for_you','cat_button_battery_check','Button battery checks','Button Battery Check',4,'Button batteries can look like tiny interesting objects, and toddlers are still likely to mouth what they find. A household sweep of remotes, thermometers, cards and toys helps remove one of the most serious hidden risks from everyday rooms.','for_you'),
  ('13-15m','13–15 months',13,15,true,'ent_cluster_safety','I’m suddenly into everything',7,true,'ent_job_13_15_home_safety','Home safety for curious climbers','More movement means more reach, more opening, more climbing and more surprises. This cluster is for the parent job around the child’s development: gates, locks, cords, batteries, furniture and toy checks. It helps your toddler explore a bigger world while the riskiest hazards stay out of reach.','for_you','cat_car_seat_size_check','Car-seat size and direction check','Car Seat Size Check',5,'Around this band, parents may wonder whether to turn a car seat forward. UK rules require height-based seats to stay rear-facing until over 15 months, and fit still depends on the child and seat limits. This is a check moment, not a hurry-up moment.','for_you'),
  ('13-15m','13–15 months',13,15,true,'ent_cluster_days','Give us a good little moment',8,true,'ent_job_13_15_day_resets','Good little outings and resets','Some days need a small reset more than another toy. A walk, library mat, park swing, bubbles, music or bath cups can give your toddler new things to point at, move towards, name and explore. These ideas keep the day moving without making parents feel they need to perform.','for_both','cat_pram_walks','Pram walks and naming games','Pram Walks',1,'A walk can become more than fresh air when you follow what your toddler notices. Naming the bus, dog, leaf or bin lorry turns ordinary movement into shared attention and language practice, with no extra setup and no pressure to entertain perfectly.','for_both'),
  ('13-15m','13–15 months',13,15,true,'ent_cluster_days','Give us a good little moment',8,true,'ent_job_13_15_day_resets','Good little outings and resets','Some days need a small reset more than another toy. A walk, library mat, park swing, bubbles, music or bath cups can give your toddler new things to point at, move towards, name and explore. These ideas keep the day moving without making parents feel they need to perform.','for_both','cat_library_baby_group','Library mats and baby groups','Library Baby Group',2,'A library session or baby group gives your toddler new sounds, faces, songs and books to explore, while giving you a gentle reset. The value is not a packed schedule, just a fresh social and language moment outside the house.','for_both'),
  ('13-15m','13–15 months',13,15,true,'ent_cluster_days','Give us a good little moment',8,true,'ent_job_13_15_day_resets','Good little outings and resets','Some days need a small reset more than another toy. A walk, library mat, park swing, bubbles, music or bath cups can give your toddler new things to point at, move towards, name and explore. These ideas keep the day moving without making parents feel they need to perform.','for_both','cat_bubbles','Bubbles','Bubbles',3,'Bubbles float, pop, disappear and come back, which makes them perfect for short attention spans. Your toddler can watch, point, reach, chase and laugh, while you add simple words like pop, more, high and gone.','for_both'),
  ('13-15m','13–15 months',13,15,true,'ent_cluster_days','Give us a good little moment',8,true,'ent_job_13_15_day_resets','Good little outings and resets','Some days need a small reset more than another toy. A walk, library mat, park swing, bubbles, music or bath cups can give your toddler new things to point at, move towards, name and explore. These ideas keep the day moving without making parents feel they need to perform.','for_both','cat_bath_cups','Bath cups and pouring games','Bath Cups',4,'Pouring water between cups gives toddlers a clear full-empty experiment. They can scoop, tip, splash and watch what happens, while you keep the activity contained. It is simple and engaging, but water always needs close adult attention.','for_both'),
  ('13-15m','13–15 months',13,15,true,'ent_cluster_days','Give us a good little moment',8,true,'ent_job_13_15_day_resets','Good little outings and resets','Some days need a small reset more than another toy. A walk, library mat, park swing, bubbles, music or bath cups can give your toddler new things to point at, move towards, name and explore. These ideas keep the day moving without making parents feel they need to perform.','for_both','cat_treasure_basket','A rotating safe treasure basket','Treasure Basket',5,'A small basket of safe, ordinary objects can make the room feel new without buying more. Swapping a few items gives your toddler choices, textures and sounds to explore, while helping you avoid turning every restless afternoon into a shopping list.','for_both'),
  ('16-18m','16–18 months',16,18,true,'ent_cluster_16_18_little_adventures','Little explorer mode',1,true,'ent_need_16_18_movement_adventure','Walking, climbing and little adventures','Your toddler may be walking further, climbing higher and turning the whole room into a route. This cluster gives that new movement a safer outlet: balls to chase, things to pull, music to dance to and simple spaces where they can practise balance without every moment feeling risky.','for_your_child','cat_soft_graspable_balls','Soft balls to roll and chase','Soft Graspable Balls',1,'Rolling a soft ball away gives your toddler a clear reason to move: step, bend, reach, fetch and try again. It can redirect throwing into something safer, while building balance, coordination and shared attention indoors, in the garden or during a quick park reset.','for_your_child'),
  ('16-18m','16–18 months',16,18,true,'ent_cluster_16_18_little_adventures','Little explorer mode',1,true,'ent_need_16_18_movement_adventure','Walking, climbing and little adventures','Your toddler may be walking further, climbing higher and turning the whole room into a route. This cluster gives that new movement a safer outlet: balls to chase, things to pull, music to dance to and simple spaces where they can practise balance without every moment feeling risky.','for_your_child','cat_pull_push_toys','Push-and-pull toys','Pull Push Toys',2,'A pull toy or steady push toy can make walking feel purposeful without rushing it. Your toddler gets to move, stop, turn and watch something follow them, which adds a little problem-solving to all that new whole-body practice.','for_your_child'),
  ('16-18m','16–18 months',16,18,true,'ent_cluster_16_18_little_adventures','Little explorer mode',1,true,'ent_need_16_18_movement_adventure','Walking, climbing and little adventures','Your toddler may be walking further, climbing higher and turning the whole room into a route. This cluster gives that new movement a safer outlet: balls to chase, things to pull, music to dance to and simple spaces where they can practise balance without every moment feeling risky.','for_your_child','cat_low_climb_tunnel','Low climbing and crawl-through play','Low Climb Tunnel',3,'Climbing onto the sofa, crawling through a tunnel or stepping over a cushion can feel thrilling at this stage. Low, supervised movement play gives your toddler a safer way to practise balance, strength and problem-solving without turning every chair into the main attraction.','for_your_child'),
  ('16-18m','16–18 months',16,18,true,'ent_cluster_16_18_little_adventures','Little explorer mode',1,true,'ent_need_16_18_movement_adventure','Walking, climbing and little adventures','Your toddler may be walking further, climbing higher and turning the whole room into a route. This cluster gives that new movement a safer outlet: balls to chase, things to pull, music to dance to and simple spaces where they can practise balance without every moment feeling risky.','for_your_child','cat_music_dance','Music and dancing games','Music Dance',4,'A song, clap or silly dance can turn a restless moment into movement practice. Your toddler can copy actions, stop and start, hear rhythm and use their whole body, while you add simple words like more, stop, fast and slow.','for_your_child'),
  ('16-18m','16–18 months',16,18,true,'ent_cluster_16_18_busy_hands','Busy little hands',2,true,'ent_need_16_18_fine_motor_two_hands','Busy hands and two-handed challenges','Little hands are getting more purposeful now. Your toddler may stack, pull, poke, turn, post and try again, often with fierce concentration. Simple two-handed challenges help build finger strength, coordination and focus, while still feeling like play rather than a task to complete.','for_your_child','cat_threading_beads','Threading beads and chunky lacing','Threading Beads',1,'Holding a bead in one hand and guiding a cord with the other is a satisfying challenge. Big, age-rated pieces let your toddler practise grip, focus and two-handed coordination, even if they spend most of the time exploring rather than threading neatly.','for_your_child'),
  ('16-18m','16–18 months',16,18,true,'ent_cluster_16_18_busy_hands','Busy little hands',2,true,'ent_need_16_18_fine_motor_two_hands','Busy hands and two-handed challenges','Little hands are getting more purposeful now. Your toddler may stack, pull, poke, turn, post and try again, often with fierce concentration. Simple two-handed challenges help build finger strength, coordination and focus, while still feeling like play rather than a task to complete.','for_your_child','cat_stacking_pegboard','Stacking pegboards and block towers','Stacking Pegboard',2,'Building a little tower, fitting pieces onto pegs and knocking everything down can be wonderfully repeatable. Your toddler practises hand control, depth, balance and early problem-solving, while learning that the same action can create a result they recognise, change and try again.','for_your_child'),
  ('16-18m','16–18 months',16,18,true,'ent_cluster_16_18_busy_hands','Busy little hands',2,true,'ent_need_16_18_fine_motor_two_hands','Busy hands and two-handed challenges','Little hands are getting more purposeful now. Your toddler may stack, pull, poke, turn, post and try again, often with fierce concentration. Simple two-handed challenges help build finger strength, coordination and focus, while still feeling like play rather than a task to complete.','for_your_child','cat_shape_sorters_puzzles','Shape sorters and first puzzles','Shape Sorters Puzzles',3,'Turning a chunky piece around and trying it in a hole can hold attention for longer than parents expect. Shape sorters and first puzzles help toddlers practise matching, rotation, patience and hand control, even when the answer takes a few attempts.','for_your_child'),
  ('16-18m','16–18 months',16,18,true,'ent_cluster_16_18_busy_hands','Busy little hands',2,true,'ent_need_16_18_fine_motor_two_hands','Busy hands and two-handed challenges','Little hands are getting more purposeful now. Your toddler may stack, pull, poke, turn, post and try again, often with fierce concentration. Simple two-handed challenges help build finger strength, coordination and focus, while still feeling like play rather than a task to complete.','for_your_child','cat_velcro_pull_hide','Pull, stick and hide toys','Velcro Pull Hide',4,'Pulling a soft piece away, sticking it back and hiding it again gives both hands a job. This kind of play supports grip strength, coordination and attention, while adding a little hide-and-find surprise that keeps the challenge playful.','for_your_child'),
  ('16-18m','16–18 months',16,18,true,'ent_cluster_16_18_cause_effect','What happens next?',3,true,'ent_need_16_18_cause_effect_problem_solving','Cause-and-effect discoveries','Rolling a car, posting a shape or opening a little door can become a tiny experiment. Your toddler is starting to connect their action with what happens next. These simple repeatable toys give them a clear result to watch, test and enjoy again.','for_your_child','cat_ramp_rolling_toys','Ramp and rolling toys','Ramp Rolling Toys',1,'Sending a car or ball down a ramp gives your toddler a clear little experiment. They can watch speed, direction and surprise, then do it again. The repetition helps build attention, anticipation and early cause-and-effect thinking in a way they can see straight away.','for_your_child'),
  ('16-18m','16–18 months',16,18,true,'ent_cluster_16_18_cause_effect','What happens next?',3,true,'ent_need_16_18_cause_effect_problem_solving','Cause-and-effect discoveries','Rolling a car, posting a shape or opening a little door can become a tiny experiment. Your toddler is starting to connect their action with what happens next. These simple repeatable toys give them a clear result to watch, test and enjoy again.','for_your_child','cat_posting_drop_boxes','Posting and drop boxes','Posting Drop Boxes',2,'Dropping a shape into a box and finding it again can become a tiny mystery. Your toddler practises aiming, releasing, waiting and checking where something went, which turns a simple container into a strong problem-solving toy with a satisfying ending.','for_your_child'),
  ('16-18m','16–18 months',16,18,true,'ent_cluster_16_18_cause_effect','What happens next?',3,true,'ent_need_16_18_cause_effect_problem_solving','Cause-and-effect discoveries','Rolling a car, posting a shape or opening a little door can become a tiny experiment. Your toddler is starting to connect their action with what happens next. These simple repeatable toys give them a clear result to watch, test and enjoy again.','for_your_child','cat_latch_busy_boards','Latches, doors and busy boards','Latch Busy Boards',3,'A toddler who wants to open every cupboard may love a safer board with simple latches, doors or switches. It gives curiosity a contained place to practise cause-and-effect, hand control and focus, while keeping real hazards out of reach.','for_your_child'),
  ('16-18m','16–18 months',16,18,true,'ent_cluster_16_18_cause_effect','What happens next?',3,true,'ent_need_16_18_cause_effect_problem_solving','Cause-and-effect discoveries','Rolling a car, posting a shape or opening a little door can become a tiny experiment. Your toddler is starting to connect their action with what happens next. These simple repeatable toys give them a clear result to watch, test and enjoy again.','for_your_child','cat_stacking_nesting_cups','Stacking and nesting cups','Stacking Nesting Cups',4,'Cups can be stacked, knocked down, nested, filled, tipped and hidden under. That flexibility makes them useful at this stage, when toddlers enjoy changing one small thing and watching what happens, especially in the bath, on the floor or with safe household objects.','for_your_child'),
  ('16-18m','16–18 months',16,18,true,'ent_cluster_16_18_words_instructions','Words are waking up',4,true,'ent_need_16_18_words_body_parts_directions','First words, body parts and little instructions','Words, pointing and understanding can jump forward around this stage. Your toddler may name familiar things, follow one simple instruction or show you what they want. Books, songs and body-part games turn those little moments into warm, repeatable language practice.','for_your_child','cat_first_word_picture_books','First-word picture books','First Word Picture Books',1,'A sturdy picture book gives your toddler something to point at, hold and hear named again. Real photos, familiar objects and short pages make it easier to repeat words, wait for their gesture and turn book time into a tiny conversation.','for_your_child'),
  ('16-18m','16–18 months',16,18,true,'ent_cluster_16_18_words_instructions','Words are waking up',4,true,'ent_need_16_18_words_body_parts_directions','First words, body parts and little instructions','Words, pointing and understanding can jump forward around this stage. Your toddler may name familiar things, follow one simple instruction or show you what they want. Books, songs and body-part games turn those little moments into warm, repeatable language practice.','for_your_child','cat_body_part_books_games','Body-part books and games','Body Part Books Games',2,'Pointing to a nose, foot or tummy can become a funny little game. Body-part books, songs and mirror moments help your toddler link words with themselves and other people, while practising one simple instruction at a time in a warm, low-pressure way.','for_your_child'),
  ('16-18m','16–18 months',16,18,true,'ent_cluster_16_18_words_instructions','Words are waking up',4,true,'ent_need_16_18_words_body_parts_directions','First words, body parts and little instructions','Words, pointing and understanding can jump forward around this stage. Your toddler may name familiar things, follow one simple instruction or show you what they want. Books, songs and body-part games turn those little moments into warm, repeatable language practice.','for_your_child','cat_songs_action_games','Songs and action games','Songs Action Games',3,'Action songs give your toddler a pattern they can predict: listen, clap, pause, copy and try a sound. The words matter, but so do the gestures and shared laughter, which make communication feel warm, physical and easy to repeat during ordinary moments.','for_your_child'),
  ('16-18m','16–18 months',16,18,true,'ent_cluster_16_18_words_instructions','Words are waking up',4,true,'ent_need_16_18_words_body_parts_directions','First words, body parts and little instructions','Words, pointing and understanding can jump forward around this stage. Your toddler may name familiar things, follow one simple instruction or show you what they want. Books, songs and body-part games turn those little moments into warm, repeatable language practice.','for_your_child','cat_naming_walks','Naming walks and object hunts','Naming Walks',4,'A walk can become a naming game when your toddler points to a dog, bus, leaf or bin lorry. Following what they notice helps link words with real objects, while giving the day a low-pressure reset outside the house.','for_your_child'),
  ('16-18m','16–18 months',16,18,true,'ent_cluster_16_18_copying_life','Copying real life',5,true,'ent_need_16_18_copying_pretend_care','Pretend, care and everyday copying','Your toddler may copy what they see: feeding a teddy, sweeping the floor, carrying a bag or pretending to drink from a cup. These small scenes help them practise memory, language and care, using the everyday life they already understand.','for_your_child','cat_doll_soft_toy_care','Soft toy and doll care play','Doll Soft Toy Care',1,'Feeding a teddy, tucking in a doll or patting a soft toy can look tiny, but it shows your toddler copying care they know. These familiar scenes help with imitation, language and early empathy without needing complicated pretend play or a big setup.','for_your_child'),
  ('16-18m','16–18 months',16,18,true,'ent_cluster_16_18_copying_life','Copying real life',5,true,'ent_need_16_18_copying_pretend_care','Pretend, care and everyday copying','Your toddler may copy what they see: feeding a teddy, sweeping the floor, carrying a bag or pretending to drink from a cup. These small scenes help them practise memory, language and care, using the everyday life they already understand.','for_your_child','cat_toy_cups_spoons','Pretend cups, spoons and food','Toy Cups Spoons',2,'Pretending to pour a drink, stir a bowl or feed a teddy links real daily routines with play. Your toddler can copy what they see, practise words like more and drink, and explore object use in a safe, familiar way.','for_your_child'),
  ('16-18m','16–18 months',16,18,true,'ent_cluster_16_18_copying_life','Copying real life',5,true,'ent_need_16_18_copying_pretend_care','Pretend, care and everyday copying','Your toddler may copy what they see: feeding a teddy, sweeping the floor, carrying a bag or pretending to drink from a cup. These small scenes help them practise memory, language and care, using the everyday life they already understand.','for_your_child','cat_play_kitchen_household_props','Play kitchen and household props','Play Kitchen Household Props',3,'A small pan, spoon, brush or play kitchen can make copying feel purposeful. Your toddler may stir, sweep, carry, open and close, turning what they watch every day into language, memory and early pretend play that feels close to real family life.','for_your_child'),
  ('16-18m','16–18 months',16,18,true,'ent_cluster_16_18_copying_life','Copying real life',5,true,'ent_need_16_18_copying_pretend_care','Pretend, care and everyday copying','Your toddler may copy what they see: feeding a teddy, sweeping the floor, carrying a bag or pretending to drink from a cup. These small scenes help them practise memory, language and care, using the everyday life they already understand.','for_your_child','cat_toddler_bag_carry','Carry bags and little errands','Toddler Bag Carry',4,'Putting a block in a bag, carrying it across the room and taking it out again can be deeply satisfying. A little carry game gives your toddler movement, purpose and simple language while they practise doing what grown-ups do.','for_your_child'),
  ('16-18m','16–18 months',16,18,true,'ent_cluster_16_18_mark_mess','Making my mark',6,true,'ent_need_16_18_scribbles_sensory','Scribbles, marks and messy little play','A scribble, splash or squish can be the whole point at this age. Your toddler is exploring what their hands can change. Chunky crayons, water marks and soft sensory play give them a safe way to notice texture, pressure, colour and movement.','for_your_child','cat_chunky_crayons','Chunky crayons and first scribbles','Chunky Crayons',1,'Scribbling is not about drawing something recognisable yet. A chunky crayon lets your toddler press, swipe, dot and notice the mark they made, building hand control and confidence through a simple, visible result they can repeat again and again on paper.','for_your_child'),
  ('16-18m','16–18 months',16,18,true,'ent_cluster_16_18_mark_mess','Making my mark',6,true,'ent_need_16_18_scribbles_sensory','Scribbles, marks and messy little play','A scribble, splash or squish can be the whole point at this age. Your toddler is exploring what their hands can change. Chunky crayons, water marks and soft sensory play give them a safe way to notice texture, pressure, colour and movement.','for_your_child','cat_water_drawing','Water drawing mats','Water Drawing',2,'A water mat lets your toddler make a mark, watch it fade and try again. It keeps early drawing low-mess, while still offering the satisfying loop of press, swipe, see and repeat that makes first marks so interesting for busy hands.','for_your_child'),
  ('16-18m','16–18 months',16,18,true,'ent_cluster_16_18_mark_mess','Making my mark',6,true,'ent_need_16_18_scribbles_sensory','Scribbles, marks and messy little play','A scribble, splash or squish can be the whole point at this age. Your toddler is exploring what their hands can change. Chunky crayons, water marks and soft sensory play give them a safe way to notice texture, pressure, colour and movement.','for_your_child','cat_play_dough_soft_clay','Soft dough and squish-safe sensory play','Play Dough Soft Clay',3,'Squashing, poking and pulling soft dough gives little fingers a different kind of workout. Your toddler explores pressure, texture and shape, while you can add simple words like soft, flat, more and again as the play unfolds beside you calmly.','for_your_child'),
  ('16-18m','16–18 months',16,18,true,'ent_cluster_16_18_mark_mess','Making my mark',6,true,'ent_need_16_18_scribbles_sensory','Scribbles, marks and messy little play','A scribble, splash or squish can be the whole point at this age. Your toddler is exploring what their hands can change. Chunky crayons, water marks and soft sensory play give them a safe way to notice texture, pressure, colour and movement.','for_your_child','cat_texture_tubs','Texture tubs and safe sensory baskets','Texture Tubs',4,'A basket with safe, large textures can hold attention without needing a complex toy. Your toddler can pick up, squeeze, sort and compare, while you name simple contrasts like soft, hard, big and small during a calm floor-play moment.','for_your_child'),
  ('16-18m','16–18 months',16,18,true,'ent_cluster_16_18_daily_practice','Daily practice, less stress',7,true,'ent_job_16_18_daily_care_practice','Messy meals and toothbrushing practice','Meals and teeth can feel messy, slow and repetitive, but they are also full of useful practice. Cups, spoons, finger foods and toothbrushing routines help your toddler join in with daily care, while giving you calmer ways to supervise and clean up.','for_both','cat_open_cup','Open or free-flow cup','Open Cup',1,'Drinking from an open or free-flow cup can be messy at first, and that is normal. A small cup gives your toddler practice holding, tipping and swallowing, while helping move daily drinks away from baby-bottle habits at their own pace.','for_both'),
  ('16-18m','16–18 months',16,18,true,'ent_cluster_16_18_daily_practice','Daily practice, less stress',7,true,'ent_job_16_18_daily_care_practice','Messy meals and toothbrushing practice','Meals and teeth can feel messy, slow and repetitive, but they are also full of useful practice. Cups, spoons, finger foods and toothbrushing routines help your toddler join in with daily care, while giving you calmer ways to supervise and clean up.','for_both','cat_first_spoons_bowls','Small spoons and stable bowls','First Spoons Bowls',2,'Trying a spoon can mean slow meals and food everywhere, but it is useful practice. A small spoon and stable bowl let your toddler scoop, miss, try again and feel involved, while you keep expectations calm, realistic and easier to clean up.','for_both'),
  ('16-18m','16–18 months',16,18,true,'ent_cluster_16_18_daily_practice','Daily practice, less stress',7,true,'ent_job_16_18_daily_care_practice','Messy meals and toothbrushing practice','Meals and teeth can feel messy, slow and repetitive, but they are also full of useful practice. Cups, spoons, finger foods and toothbrushing routines help your toddler join in with daily care, while giving you calmer ways to supervise and clean up.','for_both','cat_finger_food_snack_prep','Finger-food and snack prep','Finger Food Snack Prep',3,'Finger foods help toddlers practise picking up, chewing and feeding themselves. The parent job is the safety bit: soft textures, suitable shapes, close supervision and simple snacks that make days out, nursery handovers or hungry moments easier to manage without panic.','for_both'),
  ('16-18m','16–18 months',16,18,true,'ent_cluster_16_18_daily_practice','Daily practice, less stress',7,true,'ent_job_16_18_daily_care_practice','Messy meals and toothbrushing practice','Meals and teeth can feel messy, slow and repetitive, but they are also full of useful practice. Cups, spoons, finger foods and toothbrushing routines help your toddler join in with daily care, while giving you calmer ways to supervise and clean up.','for_both','cat_toothbrush_routine','Toddler toothbrush and teeth routine','Toothbrush Routine',4,'A tiny toothbrush, a familiar song and the same order each night can make teeth less of a battle. The aim is steady practice: brush, pause, repeat and let the routine become something your toddler recognises before bed each evening.','for_both'),
  ('16-18m','16–18 months',16,18,true,'ent_cluster_16_18_safer_home','Safer home checks',8,true,'ent_job_16_18_home_safety','Home safety for a taller, faster toddler','A 16- to 18-month-old can be suddenly taller, quicker and more determined. The same room may need a new scan for stairs, windows, cupboards, water and hidden batteries. These checks help your toddler keep exploring while the riskiest hazards stay out of reach.','for_you','cat_safety_gates','Safety gates','Safety Gates',1,'Stairs can become interesting very quickly once walking and climbing grow. Safety gates at the right places help contain the biggest fall risks, giving your toddler safer areas to explore while you stay close, supervise and keep stairways clear every day.','for_you'),
  ('16-18m','16–18 months',16,18,true,'ent_cluster_16_18_safer_home','Safer home checks',8,true,'ent_job_16_18_home_safety','Home safety for a taller, faster toddler','A 16- to 18-month-old can be suddenly taller, quicker and more determined. The same room may need a new scan for stairs, windows, cupboards, water and hidden batteries. These checks help your toddler keep exploring while the riskiest hazards stay out of reach.','for_you','cat_cupboard_locks','Cupboard locks and safer storage','Cupboard Locks',2,'Opening cupboards can be a fascinating experiment for a toddler. Locks and higher storage keep medicines, cleaning products and other dangerous items unavailable, while still leaving safer drawers and baskets for supervised exploring with everyday objects that are suitable nearby.','for_you'),
  ('16-18m','16–18 months',16,18,true,'ent_cluster_16_18_safer_home','Safer home checks',8,true,'ent_job_16_18_home_safety','Home safety for a taller, faster toddler','A 16- to 18-month-old can be suddenly taller, quicker and more determined. The same room may need a new scan for stairs, windows, cupboards, water and hidden batteries. These checks help your toddler keep exploring while the riskiest hazards stay out of reach.','for_you','cat_furniture_window_checks','Furniture, stair and window checks','Furniture Window Checks',3,'A toddler can use furniture as a ladder before you expect it. Checking window areas, trip hazards, unstable furniture and climbable surfaces helps the room keep pace with their new reach, strength and curiosity as movement gets quicker and bolder.','for_you'),
  ('16-18m','16–18 months',16,18,true,'ent_cluster_16_18_safer_home','Safer home checks',8,true,'ent_job_16_18_home_safety','Home safety for a taller, faster toddler','A 16- to 18-month-old can be suddenly taller, quicker and more determined. The same room may need a new scan for stairs, windows, cupboards, water and hidden batteries. These checks help your toddler keep exploring while the riskiest hazards stay out of reach.','for_you','cat_button_battery_check','Button battery checks','Button Battery Check',4,'Remotes, cards, scales, toys and lights can hide button batteries. A quick household sweep helps remove one of the more serious risks for a toddler who still explores with hands and mouth, especially around older-sibling toys and gadgets nearby.','for_you'),
  ('16-18m','16–18 months',16,18,true,'ent_cluster_16_18_safer_home','Safer home checks',8,true,'ent_job_16_18_home_safety','Home safety for a taller, faster toddler','A 16- to 18-month-old can be suddenly taller, quicker and more determined. The same room may need a new scan for stairs, windows, cupboards, water and hidden batteries. These checks help your toddler keep exploring while the riskiest hazards stay out of reach.','for_you','cat_bath_water_supervision','Bath and water supervision','Bath Water Supervision',5,'Bath cups and splashing can be brilliant, but water needs full adult attention every time. Keeping everything within reach before the bath helps you stay close while your toddler pours, tips and explores safely in a contained space with you.','for_you');

CREATE TEMP TABLE tmp_discover_stage1_wrappers AS
SELECT
  s.stage1_wrapper_ux_slug,
  s.stage1_wrapper_ux_label,
  NULLIF(TRIM(COALESCE(s.stage1_why_it_matters_ux_description, '')), '') AS stage1_why_it_matters_ux_description,
  NULLIF(TRIM(COALESCE(s.audience_lens, '')), '') AS audience_lens
FROM (
  SELECT
    s.*,
    ROW_NUMBER() OVER (
      PARTITION BY s.stage1_wrapper_ux_slug
      ORDER BY s.min_months ASC, s.age_band_id ASC, s.stage1_wrapper_rank_in_band ASC
    ) AS rn
  FROM tmp_discover_projection_stage s
) s
WHERE s.rn = 1;

CREATE TEMP TABLE tmp_discover_stage1_age_band_wrappers AS
SELECT
  s.age_band_id,
  s.stage1_wrapper_ux_slug,
  MIN(s.stage1_wrapper_rank_in_band) AS stage1_wrapper_rank_in_band,
  BOOL_OR(s.stage1_mapping_is_active) AS stage1_mapping_is_active
FROM tmp_discover_projection_stage s
GROUP BY s.age_band_id, s.stage1_wrapper_ux_slug;

CREATE TEMP TABLE tmp_discover_stage1_wrapper_needs AS
SELECT
  s.stage1_wrapper_ux_slug,
  s.development_need_slug,
  s.development_need_canonical_name
FROM (
  SELECT
    s.*,
    ROW_NUMBER() OVER (
      PARTITION BY s.stage1_wrapper_ux_slug
      ORDER BY s.stage2_play_ideas_rank ASC, s.min_months ASC, s.age_band_id ASC
    ) AS rn
  FROM tmp_discover_projection_stage s
) s
WHERE s.rn = 1;

CREATE TEMP TABLE tmp_discover_stage2_category_types AS
SELECT
  s.stage2_category_type_slug,
  s.stage2_category_type_name
FROM (
  SELECT
    s.*,
    ROW_NUMBER() OVER (
      PARTITION BY LOWER(TRIM(s.stage2_category_type_slug))
      ORDER BY s.min_months ASC, s.age_band_id ASC, s.stage2_play_ideas_rank ASC
    ) AS rn
  FROM tmp_discover_projection_stage s
) s
WHERE s.rn = 1;

INSERT INTO public.pl_age_bands (id, label, min_months, max_months, is_active)
SELECT DISTINCT
  s.age_band_id,
  s.age_band_label,
  s.min_months,
  s.max_months,
  s.age_band_is_active
FROM tmp_discover_projection_stage s
ON CONFLICT (id) DO UPDATE
SET
  label = EXCLUDED.label,
  min_months = EXCLUDED.min_months,
  max_months = EXCLUDED.max_months,
  is_active = EXCLUDED.is_active,
  updated_at = now();

INSERT INTO public.pl_development_needs (
  name,
  slug,
  plain_english_description,
  why_it_matters
)
SELECT
  src.development_need_canonical_name,
  src.development_need_slug,
  COALESCE(src.stage1_why_it_matters_ux_description, ''),
  COALESCE(src.stage1_why_it_matters_ux_description, '')
FROM (
  SELECT DISTINCT
    s.development_need_slug,
    s.development_need_canonical_name,
    NULLIF(TRIM(COALESCE(s.stage1_why_it_matters_ux_description, '')), '') AS stage1_why_it_matters_ux_description
  FROM tmp_discover_projection_stage s
) src
LEFT JOIN public.pl_development_needs dn_slug
  ON LOWER(COALESCE(dn_slug.slug, '')) = LOWER(src.development_need_slug)
LEFT JOIN public.pl_development_needs dn_name
  ON LOWER(COALESCE(dn_name.name, '')) = LOWER(src.development_need_canonical_name)
WHERE dn_slug.id IS NULL
  AND dn_name.id IS NULL
ON CONFLICT (slug) DO NOTHING;

UPDATE public.pl_development_needs dn
SET
  name = src.development_need_canonical_name,
  plain_english_description = COALESCE(src.stage1_why_it_matters_ux_description, ''),
  why_it_matters = COALESCE(src.stage1_why_it_matters_ux_description, ''),
  updated_at = now()
FROM (
  SELECT DISTINCT
    s.development_need_slug,
    s.development_need_canonical_name,
    NULLIF(TRIM(COALESCE(s.stage1_why_it_matters_ux_description, '')), '') AS stage1_why_it_matters_ux_description
  FROM tmp_discover_projection_stage s
) src
WHERE LOWER(COALESCE(dn.slug, '')) = LOWER(src.development_need_slug);

INSERT INTO public.pl_ux_wrappers (
  ux_slug,
  ux_label,
  ux_description,
  audience_lens,
  is_active
)
SELECT
  s.stage1_wrapper_ux_slug,
  s.stage1_wrapper_ux_label,
  s.stage1_why_it_matters_ux_description,
  s.audience_lens,
  true
FROM tmp_discover_stage1_wrappers s
ON CONFLICT (ux_slug) DO UPDATE
SET
  ux_label = EXCLUDED.ux_label,
  ux_description = EXCLUDED.ux_description,
  audience_lens = EXCLUDED.audience_lens,
  is_active = true,
  updated_at = now();

INSERT INTO public.pl_ux_wrapper_needs (
  ux_wrapper_id,
  development_need_id
)
SELECT
  uw.id AS ux_wrapper_id,
  dn.id AS development_need_id
FROM tmp_discover_stage1_wrapper_needs s
JOIN public.pl_ux_wrappers uw
  ON LOWER(uw.ux_slug) = LOWER(s.stage1_wrapper_ux_slug)
JOIN LATERAL (
  SELECT d.id
  FROM public.pl_development_needs d
  WHERE LOWER(COALESCE(d.slug, '')) = LOWER(s.development_need_slug)
     OR LOWER(COALESCE(d.name, '')) = LOWER(s.development_need_canonical_name)
  ORDER BY
    CASE WHEN LOWER(COALESCE(d.slug, '')) = LOWER(s.development_need_slug) THEN 0 ELSE 1 END,
    d.id
  LIMIT 1
) dn ON true
ON CONFLICT (ux_wrapper_id) DO UPDATE
SET
  development_need_id = EXCLUDED.development_need_id,
  updated_at = now();

UPDATE public.pl_age_band_ux_wrappers abuw
SET
  is_active = false,
  updated_at = now()
WHERE abuw.age_band_id IN (SELECT DISTINCT age_band_id FROM tmp_discover_stage1_age_band_wrappers)
  AND NOT EXISTS (
    SELECT 1
    FROM tmp_discover_stage1_age_band_wrappers s
    JOIN public.pl_ux_wrappers uw ON LOWER(uw.ux_slug) = LOWER(s.stage1_wrapper_ux_slug)
    WHERE s.age_band_id = abuw.age_band_id
      AND uw.id = abuw.ux_wrapper_id
  );

INSERT INTO public.pl_age_band_ux_wrappers (
  age_band_id,
  ux_wrapper_id,
  rank,
  is_active
)
SELECT
  s.age_band_id,
  uw.id,
  s.stage1_wrapper_rank_in_band,
  s.stage1_mapping_is_active
FROM tmp_discover_stage1_age_band_wrappers s
JOIN public.pl_ux_wrappers uw
  ON LOWER(uw.ux_slug) = LOWER(s.stage1_wrapper_ux_slug)
ON CONFLICT (age_band_id, ux_wrapper_id) DO UPDATE
SET
  rank = EXCLUDED.rank,
  is_active = EXCLUDED.is_active,
  updated_at = now();

INSERT INTO public.pl_category_types (
  slug,
  label,
  name,
  description,
  safety_notes
)
SELECT
  src.stage2_category_type_slug,
  src.stage2_category_type_name,
  src.stage2_category_type_name,
  NULL,
  NULL
FROM tmp_discover_stage2_category_types src
LEFT JOIN public.pl_category_types ct_slug
  ON LOWER(COALESCE(ct_slug.slug, '')) = LOWER(src.stage2_category_type_slug)
WHERE ct_slug.id IS NULL
ON CONFLICT (slug) DO NOTHING;

CREATE TEMP TABLE tmp_discover_resolved_need_category AS
SELECT DISTINCT
  s.age_band_id,
  dn.id AS development_need_id,
  ct.id AS category_type_id,
  s.stage2_play_ideas_rank AS rank,
  NULLIF(TRIM(COALESCE(s.stage2_play_idea_mapping_rationale, '')), '') AS rationale,
  NULLIF(TRIM(COALESCE(s.stage2_category_type_label, '')), '') AS display_label,
  NULLIF(TRIM(COALESCE(s.category_audience_lens, '')), '') AS audience_lens
FROM tmp_discover_projection_stage s
JOIN LATERAL (
  SELECT d.id
  FROM public.pl_development_needs d
  WHERE LOWER(COALESCE(d.slug, '')) = LOWER(s.development_need_slug)
     OR LOWER(COALESCE(d.name, '')) = LOWER(s.development_need_canonical_name)
  ORDER BY
    CASE WHEN LOWER(COALESCE(d.slug, '')) = LOWER(s.development_need_slug) THEN 0 ELSE 1 END,
    d.id
  LIMIT 1
) dn ON true
JOIN LATERAL (
  SELECT c.id
  FROM public.pl_category_types c
  WHERE LOWER(COALESCE(c.slug, '')) = LOWER(s.stage2_category_type_slug)
     OR LOWER(COALESCE(c.name, '')) = LOWER(s.stage2_category_type_name)
     OR LOWER(COALESCE(c.label, '')) = LOWER(s.stage2_category_type_label)
  ORDER BY
    CASE
      WHEN LOWER(COALESCE(c.slug, '')) = LOWER(s.stage2_category_type_slug) THEN 0
      WHEN LOWER(COALESCE(c.name, '')) = LOWER(s.stage2_category_type_name) THEN 1
      ELSE 2
    END,
    c.id
  LIMIT 1
) ct ON true;

UPDATE public.pl_age_band_development_need_category_types m
SET
  is_active = false,
  updated_at = now()
WHERE m.age_band_id IN (SELECT DISTINCT age_band_id FROM tmp_discover_projection_stage)
  AND NOT EXISTS (
    SELECT 1
    FROM tmp_discover_resolved_need_category r
    WHERE r.age_band_id = m.age_band_id
      AND r.development_need_id = m.development_need_id
      AND r.category_type_id = m.category_type_id
  );

INSERT INTO public.pl_age_band_development_need_category_types (
  age_band_id,
  development_need_id,
  category_type_id,
  rank,
  rationale,
  display_label,
  audience_lens,
  is_active
)
SELECT
  r.age_band_id,
  r.development_need_id,
  r.category_type_id,
  r.rank,
  r.rationale,
  r.display_label,
  r.audience_lens,
  true
FROM tmp_discover_resolved_need_category r
ON CONFLICT (age_band_id, development_need_id, category_type_id) DO UPDATE
SET
  rank = EXCLUDED.rank,
  rationale = EXCLUDED.rationale,
  display_label = EXCLUDED.display_label,
  audience_lens = EXCLUDED.audience_lens,
  is_active = true,
  updated_at = now();

UPDATE public.pl_age_band_category_type_products p
SET
  is_active = false,
  updated_at = now()
WHERE p.age_band_id IN (SELECT DISTINCT age_band_id FROM tmp_discover_projection_stage);

DO $$
DECLARE
  v_rows_loaded INTEGER;
  v_rows_1_3m INTEGER;
  v_clusters_1_3m INTEGER;
  v_rows_13_15m INTEGER;
  v_clusters_13_15m INTEGER;
  v_rows_16_18m INTEGER;
  v_clusters_16_18m INTEGER;
  v_rows_4_6m INTEGER;
  v_clusters_4_6m INTEGER;
  v_rows_9_12m INTEGER;
  v_clusters_9_12m INTEGER;
  v_stage3_active INTEGER;
BEGIN
  SELECT COUNT(*) INTO v_rows_loaded FROM tmp_discover_projection_stage;
  SELECT COUNT(*) INTO v_rows_1_3m FROM tmp_discover_projection_stage WHERE age_band_id = '1-3m';
  SELECT COUNT(DISTINCT stage1_wrapper_ux_slug) INTO v_clusters_1_3m
  FROM tmp_discover_projection_stage WHERE age_band_id = '1-3m';
  SELECT COUNT(*) INTO v_rows_13_15m FROM tmp_discover_projection_stage WHERE age_band_id = '13-15m';
  SELECT COUNT(DISTINCT stage1_wrapper_ux_slug) INTO v_clusters_13_15m
  FROM tmp_discover_projection_stage WHERE age_band_id = '13-15m';
  SELECT COUNT(*) INTO v_rows_16_18m FROM tmp_discover_projection_stage WHERE age_band_id = '16-18m';
  SELECT COUNT(DISTINCT stage1_wrapper_ux_slug) INTO v_clusters_16_18m
  FROM tmp_discover_projection_stage WHERE age_band_id = '16-18m';
  SELECT COUNT(*) INTO v_rows_4_6m FROM tmp_discover_projection_stage WHERE age_band_id = '4-6m';
  SELECT COUNT(DISTINCT stage1_wrapper_ux_slug) INTO v_clusters_4_6m
  FROM tmp_discover_projection_stage WHERE age_band_id = '4-6m';
  SELECT COUNT(*) INTO v_rows_9_12m FROM tmp_discover_projection_stage WHERE age_band_id = '9-12m';
  SELECT COUNT(DISTINCT stage1_wrapper_ux_slug) INTO v_clusters_9_12m
  FROM tmp_discover_projection_stage WHERE age_band_id = '9-12m';
  SELECT COUNT(*) INTO v_stage3_active
  FROM public.pl_age_band_category_type_products
  WHERE age_band_id IN ('1-3m', '13-15m', '16-18m', '4-6m', '9-12m')
    AND is_active = true;

  RAISE NOTICE 'Discover projection rows loaded: % (expected 197)', v_rows_loaded;
  RAISE NOTICE '1-3m rows: % (expected 42), clusters: % (expected 10)', v_rows_1_3m, v_clusters_1_3m;
  RAISE NOTICE '13-15m rows: % (expected 40), clusters: % (expected 8)', v_rows_13_15m, v_clusters_13_15m;
  RAISE NOTICE '16-18m rows: % (expected 33), clusters: % (expected 8)', v_rows_16_18m, v_clusters_16_18m;
  RAISE NOTICE '4-6m rows: % (expected 34), clusters: % (expected 8)', v_rows_4_6m, v_clusters_4_6m;
  RAISE NOTICE '9-12m rows: % (expected 48), clusters: % (expected 8)', v_rows_9_12m, v_clusters_9_12m;
  RAISE NOTICE 'Active Stage 3 mappings (expected 0): %', v_stage3_active;

  IF v_rows_loaded <> 197 THEN
    RAISE EXCEPTION 'Row count validation failed';
  END IF;
  IF v_rows_1_3m <> 42 THEN
    RAISE EXCEPTION 'Row count validation failed for 1-3m';
  END IF;
  IF v_rows_13_15m <> 40 THEN
    RAISE EXCEPTION 'Row count validation failed for 13-15m';
  END IF;
  IF v_rows_16_18m <> 33 THEN
    RAISE EXCEPTION 'Row count validation failed for 16-18m';
  END IF;
  IF v_rows_4_6m <> 34 THEN
    RAISE EXCEPTION 'Row count validation failed for 4-6m';
  END IF;
  IF v_rows_9_12m <> 48 THEN
    RAISE EXCEPTION 'Row count validation failed for 9-12m';
  END IF;
  IF v_clusters_1_3m <> 10 THEN
    RAISE EXCEPTION 'Cluster count validation failed for 1-3m';
  END IF;
  IF v_clusters_13_15m <> 8 THEN
    RAISE EXCEPTION 'Cluster count validation failed for 13-15m';
  END IF;
  IF v_clusters_16_18m <> 8 THEN
    RAISE EXCEPTION 'Cluster count validation failed for 16-18m';
  END IF;
  IF v_clusters_4_6m <> 8 THEN
    RAISE EXCEPTION 'Cluster count validation failed for 4-6m';
  END IF;
  IF v_clusters_9_12m <> 8 THEN
    RAISE EXCEPTION 'Cluster count validation failed for 9-12m';
  END IF;
END $$;

COMMIT;

